   147→impl App {
   148→    fn load_or_init(project_root: Utf8PathBuf) -> Result<Self> {
   149→        let state_dir = project_root.join(".dellij");
   150→        fs::create_dir_all(state_dir.join("hooks"))
   151→            .with_context(|| format!("creating {}", state_dir.join("hooks")))?;
   152→        fs::create_dir_all(state_dir.join("status"))
   153→            .with_context(|| format!("creating {}", state_dir.join("status")))?;
   154→        fs::create_dir_all(state_dir.join("layouts"))
   155→            .with_context(|| format!("creating {}", state_dir.join("layouts")))?;
   156→
   157→        let config_path = state_dir.join("dellij.json");
   158→        let config = if config_path.exists() {
   159→            let raw = fs::read_to_string(&config_path)
   160→                .with_context(|| format!("reading {}", config_path))?;
   161→            serde_json::from_str(&raw).with_context(|| format!("parsing {}", config_path))?
   162→        } else {
   163→            let config = Config::new(project_root.clone());
   164→            write_json(&config_path, &config)?;
   165→            config
   166→        };
   167→
   168→        Ok(Self {
   169→            project_root,
   170→            state_dir,
   171→            config_path,
   172→            config,
   173→        })
   174→    }
   175→
   176→    fn run(&mut self, command: Commands) -> Result<()> {
   177→        match command {
   178→            Commands::Init => self.init(),
   179→            Commands::Open(args) => self.open(args),
   180→            Commands::New(args) => self.new_workspace(args),
   181→            Commands::List => self.list(),
   182→            Commands::Run(args) => self.run_in_workspace(args),
   183→            Commands::Bookmark { command } => self.bookmark(command),
   184→            Commands::Show(reference) => self.show(&reference.slug),
   185→            Commands::Status(args) => self.update_status(args),
   186→            Commands::Close(args) => self.close(args),
   187→            Commands::Layout(reference) => self.print_layout(&reference.slug),
   188→            Commands::Doctor => self.doctor(),
   189→        }
   190→    }
   191→
   192→    fn init(&mut self) -> Result<()> {
   193→        self.ensure_zellij_available()?;
   194→        self.save()?;
   195→        println!("Initialized dellij at {}", self.state_dir);
   196→        println!("Workspaces root: {}", self.workspace_root());
   197→        println!("Hooks dir: {}", self.state_dir.join("hooks"));
   198→        println!("Session: {}", self.session_name());
   199→        Ok(())
   200→    }
   201→
   202→    fn new_workspace(&mut self, args: NewArgs) -> Result<()> {
   203→        self.ensure_zellij_available()?;
   204→        let should_open = args.open;
   205→        let workspace = self.new_workspace_from_args(args)?;
   206→        if should_open {
   207→            self.open_workspace_tab(&workspace)?;
   208→        }
   209→        Ok(())
   210→    }
   211→
   212→    fn open(&mut self, args: OpenArgs) -> Result<()> {
   213→        self.ensure_zellij_available()?;
   214→
   215→        if args.create {
   216→            let prompt = args
   217→                .prompt
   218→                .clone()
   219→                .with_context(|| "--create requires --prompt")?;
   220→            let slug = {
   221→                let new_args = NewArgs {
   222→                    prompt,
   223→                    name: args.name.clone(),
   224→                    agent: args.agent.clone(),
   225→                    base_branch: None,
   226→                    port: args.port.clone(),
   227→                    url: args.url.clone(),
   228→                    setup: args.setup,
   229→                    open: false,
   230→                };
   231→                self.new_workspace_from_args(new_args)?.slug
   232→            };
   233→            return self.open_workspace(&slug);
   234→        }
   235→
   236→        match args.slug {
   237→            Some(slug) => self.open_workspace(&slug),
   238→            None => self.open_control_session(),
   239→        }
   240→    }
   241→
   242→    fn new_workspace_from_args(&mut self, args: NewArgs) -> Result<Workspace> {
   243→        let agent = args
   244→            .agent
   245→            .unwrap_or_else(|| self.config.settings.default_agent.clone());
   246→        let slug = slugify(args.name.as_deref().unwrap_or(&args.prompt), &agent);
   247→        if self.config.workspaces.iter().any(|w| w.slug == slug) {
   248→            bail!("workspace '{slug}' already exists");
   249→        }
   250→
   251→        let base_branch = match args.base_branch {
   252→            Some(branch) => branch,
   253→            None => detect_base_branch(&self.project_root)
   254→                .unwrap_or_else(|_| self.config.settings.base_branch.clone()),
   255→        };
   256→        let branch_name = format!("{}{}", self.config.settings.branch_prefix, slug);
   257→        let worktree_path = self.workspace_root().join(&slug);
   258→        fs::create_dir_all(self.workspace_root())
   259→            .with_context(|| format!("creating {}", self.workspace_root()))?;
   260→
   261→        git(
   262→            &self.project_root,
   263→            &[
   264→                "worktree",
   265→                "add",
   266→                "-b",
   267→                &branch_name,
   268→                worktree_path.as_str(),
   269→                &base_branch,
   270→            ],
   271→        )
   272→        .with_context(|| format!("creating git worktree for {slug}"))?;
   273→
   274→        let workspace = Workspace {
   275→            slug: slug.clone(),
   276→            prompt: args.prompt.clone(),
   277→            agent: agent.clone(),
   278→            branch_name,
   279→            base_branch,
   280→            worktree_path: worktree_path.clone(),
   281→            status: WorkspaceStatus::Working,
   282→            created_at: Utc::now(),
   283→            updated_at: Utc::now(),
   284→            ports: args.port,
   285→            urls: args.url,
   286→            last_command: Some(render_agent_command(&agent, &args.prompt)),
   287→            notes: Vec::new(),
   288→        };
   289→
   290→        self.write_status_file(&workspace)?;
   291→        self.write_layout_file(&workspace)?;
   292→        self.config.workspaces.push(workspace.clone());
   293→        self.save()?;
   294→
   295→        if args.setup {
   296→            self.run_hook("workspace_setup", &workspace)?;
   297→        }
   298→
   299→        println!("Created workspace {}", workspace.slug);
   300→        println!("  path: {}", workspace.worktree_path);
   301→        println!("  branch: {}", workspace.branch_name);
   302→        println!("  agent command: {}", workspace.last_command.as_deref().unwrap_or(""));
   303→        Ok(workspace)
   304→    }
   305→
   306→    fn list(&self) -> Result<()> {
   307→        if self.config.workspaces.is_empty() {
   308→            println!("No workspaces tracked for {}", self.project_root);
   309→            return Ok(());
   310→        }
   311→
   312→        for workspace in &self.config.workspaces {
   313→            let ports = if workspace.ports.is_empty() {
   314→                String::from("-")
   315→            } else {
   316→                workspace
   317→                    .ports
   318→                    .iter()
   319→                    .map(u16::to_string)
   320→                    .collect::<Vec<_>>()
   321→                    .join(",")
   322→            };
   323→            println!(
   324→                "{:16} {:10} {:12} {:12} {}",
   325→                workspace.slug,
   326→                workspace.status,
   327→                workspace.agent,
   328→                ports,
   329→                workspace.worktree_path
   330→            );
   331→        }
   332→        Ok(())
   333→    }
   334→
   335→    fn show(&self, slug: &str) -> Result<()> {
   336→        let workspace = self.workspace(slug)?;
   337→        println!("{}", serde_json::to_string_pretty(workspace)?);
   338→        Ok(())
   339→    }
   340→
   341→    fn bookmark(&mut self, command: BookmarkCommand) -> Result<()> {
   342→        match command {
   343→            BookmarkCommand::Add(args) => {
   344→                self.config
   345→                    .bookmarks
   346→                    .retain(|bookmark| bookmark.name != args.name);
   347→                self.config.bookmarks.push(Bookmark {
   348→                    name: args.name,
   349→                    command: args.command,
   350→                    description: args.description,
   351→                });
   352→                self.config
   353→                    .bookmarks
   354→                    .sort_by(|left, right| left.name.cmp(&right.name));
   355→                self.save()?;
   356→                println!("Saved bookmark");
   357→            }
   358→            BookmarkCommand::List => {
   359→                if self.config.bookmarks.is_empty() {
   360→                    println!("No bookmarks saved");
   361→                } else {
   362→                    for bookmark in &self.config.bookmarks {
   363→                        println!(
   364→                            "{:16} {}{}",
   365→                            bookmark.name,
   366→                            bookmark.command,
   367→                            bookmark
   368→                                .description
   369→                                .as_ref()
   370→                                .map(|desc| format!("  # {desc}"))
   371→                                .unwrap_or_default()
   372→                        );
   373→                    }
   374→                }
   375→            }
   376→            BookmarkCommand::Remove(reference) => {
   377→                let before = self.config.bookmarks.len();
   378→                self.config
   379→                    .bookmarks
   380→                    .retain(|bookmark| bookmark.name != reference.name);
   381→                if self.config.bookmarks.len() == before {
   382→                    bail!("bookmark '{}' not found", reference.name);
   383→                }
   384→                self.save()?;
   385→                println!("Removed bookmark {}", reference.name);
   386→            }
   387→        }
   388→        Ok(())
   389→    }
   390→
   391→    fn run_in_workspace(&self, args: RunArgs) -> Result<()> {
   392→        let workspace = self.workspace(&args.slug)?;
   393→        let command = self.resolve_bookmark_or_command(&args.target)?;
   394→
   395→        if inside_zellij() {
   396→            let mut zellij_args = vec!["run"];
   397→            if args.floating {
   398→                zellij_args.push("--floating");
   399→            }
   400→            if args.close_on_exit {
   401→                zellij_args.push("--close-on-exit");
   402→            }
   403→            zellij_args.extend_from_slice(&["--cwd", workspace.worktree_path.as_str(), "--name", &args.target]);
   404→            zellij_args.extend_from_slice(&["--", "bash", "-lc", &command]);
   405→            self.zellij(&zellij_args)?;
   406→        } else {
   407→            let status = Command::new("bash")
   408→                .args(["-lc", &command])
   409→                .current_dir(&workspace.worktree_path)
   410→                .status()
   411→                .with_context(|| format!("running command in {}", workspace.worktree_path))?;
   412→            if !status.success() {
   413→                bail!("command exited with {}", status);
   414→            }
   415→        }
   416→        Ok(())
   417→    }
   418→
   419→    fn update_status(&mut self, args: StatusArgs) -> Result<()> {
   420→        let workspace = self.workspace_mut(&args.slug)?;
   421→        workspace.status = args.state;
   422→        workspace.updated_at = Utc::now();
   423→        if let Some(note) = args.note {
   424→            workspace.notes.push(note);
   425→        }
   426→        let snapshot = workspace.clone();
   427→        self.write_status_file(&snapshot)?;
   428→        self.save()?;
   429→        println!("{} -> {}", snapshot.slug, snapshot.status);
   430→        Ok(())
   431→    }
   432→
   433→    fn close(&mut self, args: CloseArgs) -> Result<()> {
   434→        let idx = self
   435→            .config
   436→            .workspaces
   437→            .iter()
   438→            .position(|w| w.slug == args.slug)
   439→            .with_context(|| format!("workspace '{}' not found", args.slug))?;
   440→        let workspace = self.config.workspaces[idx].clone();
   441→
   442→        if args.teardown {
   443→            self.run_hook("workspace_teardown", &workspace)?;
   444→        }
   445→
   446→        if !args.keep_worktree {
   447→            git(
   448→                &self.project_root,
   449→                &["worktree", "remove", "--force", workspace.worktree_path.as_str()],
   450→            )
   451→            .with_context(|| format!("removing worktree {}", workspace.worktree_path))?;
   452→        }
   453→
   454→        let status_path = self.state_dir.join("status").join(format!("{}.json", workspace.slug));
   455→        if status_path.exists() {
   456→            fs::remove_file(&status_path).with_context(|| format!("removing {}", status_path))?;
   457→        }
   458→
   459→        self.config.workspaces.remove(idx);
   460→        self.save()?;
   461→        println!("Closed workspace {}", workspace.slug);
   462→        Ok(())
   463→    }
   464→
   465→    fn print_layout(&self, slug: &str) -> Result<()> {
   466→        let workspace = self.workspace(slug)?;
   467→        let layout = self.render_layout(workspace);
   468→        println!("{layout}");
   469→        Ok(())
   470→    }
   471→
   472→    fn doctor(&self) -> Result<()> {
   473→        let git_ok = command_exists("git");
   474→        let zellij_ok = command_exists("zellij");
   475→        let hooks_dir = self.state_dir.join("hooks");
   476→        println!("project_root: {}", self.project_root);
   477→        println!("session: {}", self.session_name());
   478→        println!("git: {}", yes_no(git_ok));
   479→        println!("zellij: {}", yes_no(zellij_ok));
   480→        println!("hooks_dir: {}", yes_no(hooks_dir.exists()));
   481→        println!("workspace_count: {}", self.config.workspaces.len());
   482→        println!("bookmark_count: {}", self.config.bookmarks.len());
   483→        Ok(())
   484→    }
   485→
   486→    fn workspace_root(&self) -> Utf8PathBuf {
   487→        self.project_root.join(&self.config.settings.workspace_root)
   488→    }
   489→
   490→    fn workspace(&self, slug: &str) -> Result<&Workspace> {
   491→        self.config
   492→            .workspaces
   493→            .iter()
   494→            .find(|workspace| workspace.slug == slug)
   495→            .with_context(|| format!("workspace '{slug}' not found"))
   496→    }
   497→
   498→    fn workspace_mut(&mut self, slug: &str) -> Result<&mut Workspace> {
   499→        self.config
   500→            .workspaces
   501→            .iter_mut()
   502→            .find(|workspace| workspace.slug == slug)
   503→            .with_context(|| format!("workspace '{slug}' not found"))
   504→    }
   505→
   506→    fn write_status_file(&self, workspace: &Workspace) -> Result<()> {
   507→        let status = StatusFile {
   508→            slug: workspace.slug.clone(),
   509→            status: workspace.status,
   510→            updated_at: workspace.updated_at,
   511→            agent: workspace.agent.clone(),
   512→        };
   513→        write_json(
   514→            &self
   515→                .state_dir
   516→                .join("status")
   517→                .join(format!("{}.json", workspace.slug)),
   518→            &status,
   519→        )
   520→    }
   521→
   522→    fn write_layout_file(&self, workspace: &Workspace) -> Result<Utf8PathBuf> {
   523→        let path = self
   524→            .state_dir
   525→            .join("layouts")
   526→            .join(format!("{}.kdl", workspace.slug));
   527→        fs::write(&path, self.render_layout(workspace))
   528→            .with_context(|| format!("writing {}", path))?;
   529→        Ok(path)
   530→    }
   531→
   532→    fn render_layout(&self, workspace: &Workspace) -> String {
   533→        format!(
   534→            "layout {{\n  pane split_direction=\"vertical\" {{\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"{agent_cmd}\" }}\n    pane command=\"bash\" cwd=\"{cwd}\"\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"git status --short --branch\" }}\n  }}\n}}\n",
   535→            cwd = workspace.worktree_path,
   536→            agent_cmd = shell_escape(workspace.last_command.as_deref().unwrap_or("bash"))
   537→        )
   538→    }
