   616→    fn session_exists(&self, session: &str) -> Result<bool> {
   617→        let output = Command::new("zellij")
   618→            .args(["list-sessions"])
   619→            .current_dir(&self.project_root)
   620→            .output()
   621→            .context("listing zellij sessions")?;
   622→        if !output.status.success() {
   623→            bail!("zellij list-sessions failed");
   624→        }
