   629→    fn zellij(&self, args: &[&str]) -> Result<()> {
   630→        let status = Command::new("zellij")
   631→            .args(args)
   632→            .current_dir(&self.project_root)
   633→            .status()
   634→            .with_context(|| format!("running zellij {}", args.join(" ")))?;
   635→        if !status.success() {
