   659→
   660→        let mut command = Command::new(&hook_path);
   661→        command.current_dir(&workspace.worktree_path);
   662→        command.env("DELLIJ_ROOT", self.project_root.as_str());
   663→        command.env("DELLIJ_STATE_DIR", self.state_dir.as_str());
