   667→        command.env("DELLIJ_WORKTREE_PATH", workspace.worktree_path.as_str());
   668→        command.env("DELLIJ_PROMPT", &workspace.prompt);
   669→        let status = command
   670→            .status()
   671→            .with_context(|| format!("running hook {}", hook_path))?;
   672→        if !status.success() {
   673→            bail!("hook {} exited with {}", hook_path, status);
   674→        }
   675→        Ok(())
   676→    }
