   780→fn resolve_project_root(project_root: Option<Utf8PathBuf>) -> Result<Utf8PathBuf> {
   781→    if let Some(project_root) = project_root {
   782→        return Ok(project_root);
   783→    }
   784→
   785→    let cwd = env::current_dir().context("resolving current directory")?;
   786→    let cwd = Utf8PathBuf::from_path_buf(cwd).map_err(|_| anyhow::anyhow!("cwd is not valid utf-8"))?;
   787→    if let Ok(root) = git_output(&cwd, &["rev-parse", "--show-toplevel"]) {
   788→        return Ok(Utf8PathBuf::from(root.trim()));
   789→    }
   790→    Ok(cwd)
   791→}
