   793→fn detect_base_branch(project_root: &Utf8Path) -> Result<String> {
   794→    let output = git_output(
   795→        project_root,
   796→        &["symbolic-ref", "refs/remotes/origin/HEAD", "--short"],
   797→    )?;
   798→    Ok(output.trim().trim_start_matches("origin/").to_string())
   799→}
