   801→fn git(project_root: &Utf8Path, args: &[&str]) -> Result<()> {
   802→    let status = Command::new("git")
   803→        .args(args)
   804→        .current_dir(project_root)
   805→        .stdin(Stdio::null())
   806→        .status()
   807→        .with_context(|| format!("running git {}", args.join(" ")))?;
   808→    if !status.success() {
   809→        bail!("git {} exited with {}", args.join(" "), status);
   810→    }
   811→    Ok(())
   812→}
   813→
   814→fn git_output(project_root: &Utf8Path, args: &[&str]) -> Result<String> {
   815→    let output = Command::new("git")
   816→        .args(args)
   817→        .current_dir(project_root)
   818→        .stdin(Stdio::null())
   819→        .output()
   820→        .with_context(|| format!("running git {}", args.join(" ")))?;
   821→    if !output.status.success() {
   822→        bail!(
   823→            "git {} exited with {}: {}",
   824→            args.join(" "),
   825→            output.status,
   826→            String::from_utf8_lossy(&output.stderr)
   827→        );
   828→    }
   829→    Ok(String::from_utf8(output.stdout)?.trim().to_string())
   830→}
