   832→fn write_json<T: Serialize>(path: &Utf8Path, value: &T) -> Result<()> {
   833→    let body = serde_json::to_string_pretty(value)?;
   834→    fs::write(path, body).with_context(|| format!("writing {}", path))?;
   835→    Ok(())
   836→}
