   856→fn render_agent_command(agent: &str, prompt: &str) -> String {
   857→    match agent {
   858→        "codex" => format!("codex \"{}\"", shell_escape(prompt)),
   859→        "claude" => format!("claude \"{}\"", shell_escape(prompt)),
   860→        "aider" => format!("aider --message \"{}\"", shell_escape(prompt)),
   861→        other => format!("{other} \"{}\"", shell_escape(prompt)),
   862→    }
   863→}
   864→
   865→fn shell_escape(input: &str) -> String {
   866→    input.replace('\\', "\\\\").replace('"', "\\\"")
   867→}
