   869→fn command_exists(name: &str) -> bool {
   870→    env::var_os("PATH")
   871→        .and_then(|paths| {
   872→            env::split_paths(&paths).find(|dir| {
   873→                let candidate = dir.join(name);
   874→                candidate.is_file() || is_windows_exe(&candidate)
   875→            })
   876→        })
   877→        .is_some()
   878→}
