   884→fn is_windows_exe(candidate: &Path) -> bool {
   885→    ["exe", "bat", "cmd"]
   886→        .iter()
   887→        .map(|ext| candidate.with_extension(ext))
   888→        .any(|path| path.is_file())
   889→}
