    34→impl ZellijPlugin for DellijStatusPlugin {
    35→    fn load(&mut self, configuration: BTreeMap<String, String>) {
    36→        self.config_dir = configuration
    37→            .get("config_dir")
    38→            .cloned()
    39→            .unwrap_or_default();
    40→
    41→        // This plugin is only a status ribbon; it should never take keyboard focus.
    42→        set_selectable(false);
    43→
    44→        request_permission(&[PermissionType::ReadApplicationState]);
    45→
    46→        subscribe(&[
    47→            EventType::Timer,
    48→            EventType::TabUpdate,
    49→            EventType::PermissionRequestResult,
    50→        ]);
    51→
    52→        set_timeout(2.0);
    53→    }
    54→
    55→    fn update(&mut self, event: Event) -> bool {
    56→        let mut should_render = false;
    57→        match event {
    58→            Event::Timer(_elapsed) => {
    59→                set_timeout(2.0);
    60→                self.tick += 1;
    61→                self.agents = self.read_status_files();
    62→                should_render = true;
    63→            }
    64→            Event::TabUpdate(tab_infos) => {
    65→                for tab in tab_infos {
    66→                    if tab.active {
    67→                        self.active_tab = Some(tab.name);
    68→                        should_render = true;
    69→                        break;
    70→                    }
    71→                }
    72→            }
    73→            Event::PermissionRequestResult(status) => {
    74→                if status == PermissionStatus::Granted {
    75→                    should_render = true;
    76→                }
    77→            }
    78→            _ => {}
    79→        }
    80→        should_render
    81→    }
    82→
    83→    fn render(&mut self, _rows: usize, _cols: usize) {
    84→        if self.config_dir.is_empty() {
    85→            println!("dellij: no config_dir configured");
    86→            return;
    87→        }
    88→
    89→        let agent_count = self.agents.len();
    90→        if agent_count == 0 {
    91→            return;
    92→        }
    93→
    94→        let mut combined_text = String::new();
    95→        combined_text.push_str(" dellij ");
    96→
    97→        // Tracking byte ranges for colors
    98→        // Format: (index_level, start_byte, end_byte)
    99→        let mut styling = vec![(2, 0, 8)]; // Brand in Green/Cyan
   100→
   101→        let mut current_pos = 8;
   102→        for agent in &self.agents {
   103→            let is_active = self.active_tab.as_ref() == Some(&agent.slug);
   104→            let status_idx = status_to_index(&agent.status);
   105→
   106→            let segment = format!(" {} ● {} ", agent.short_label, agent.status);
   107→            let start = current_pos;
   108→            let end = current_pos + segment.len();
   109→
   110→            // Base color for the agent segment
   111→            if is_active {
   112→                styling.push((0, start, end)); // Active in Primary
   113→            } else {
   114→                styling.push((1, start, end)); // Inactive in Secondary
   115→            }
   116→
   117→            // Dot color override
   118→            // Dot is at space(1) + label(2) + space(1) = 4 bytes from start of segment
   119→            // Dot "●" is 3 bytes
   120→            styling.push((status_idx, start + 4, start + 7));
   121→
   122→            combined_text.push_str(&segment);
   123→            current_pos = end;
   124→        }
   125→
   126→        let mut text_component = Text::new(combined_text);
   127→        for (idx, start, end) in styling {
   128→            text_component = text_component.color_range(idx, start..end);
   129→        }
   130→
   131→        print_ribbon(text_component);
   132→    }
   133→}
   134→
   135→fn status_to_index(status: &str) -> usize {
   136→    match status {
   137→        "working" => 3, // Yellow
   138→        "waiting" => 7, // Cyan
   139→        "error" => 4,   // Red
   140→        "done" => 2,    // Green
   141→        _ => 2,
   142→    }
   143→}
