   145→impl DellijStatusPlugin {
   146→    fn read_status_files(&self) -> Vec<AgentInfo> {
   147→        let status_dir = Path::new(&self.config_dir).join("status");
   148→
   149→        let read_dir = match fs::read_dir(&status_dir) {
   150→            Ok(rd) => rd,
   151→            Err(_) => return Vec::new(),
   152→        };
   153→
   154→        let mut agents = Vec::new();
   155→
   156→        for entry in read_dir.flatten() {
   157→            let path = entry.path();
   158→            if path.extension().and_then(|e| e.to_str()) != Some("json") {
   159→                continue;
   160→            }
   161→
   162→            let slug = path
   163→                .file_stem()
   164→                .and_then(|s| s.to_str())
   165→                .unwrap_or("")
   166→                .to_string();
   167→
   168→            if slug.is_empty() {
   169→                continue;
   170→            }
   171→
   172→            let content = match fs::read_to_string(&path) {
   173→                Ok(c) => c,
   174→                Err(_) => continue,
   175→            };
   176→
   177→            let parsed: StatusFile = match serde_json::from_str(&content) {
   178→                Ok(p) => p,
   179→                Err(_) => continue,
   180→            };
   181→
   182→            let short_label = derive_short_label(&slug);
   183→
   184→            agents.push(AgentInfo {
   185→                slug: slug.clone(),
   186→                short_label,
   187→                status: parsed.status,
   188→            });
   189→        }
   190→
   191→        agents.sort_by(|a, b| a.slug.cmp(&b.slug));
   192→        agents
   193→    }
   194→}
   195→
   196→fn derive_short_label(slug: &str) -> String {
   197→    let known_suffixes: &[(&str, &str)] = &[
   198→        ("claude-code", "cc"),
   199→        ("opencode", "oc"),
   200→        ("codex", "cx"),
   201→        ("cline", "cl"),
   202→        ("gemini", "gm"),
   203→        ("qwen", "qn"),
   204→        ("amp", "ap"),
   205→        ("pi", "pi"),
   206→        ("cursor", "cr"),
   207→        ("copilot", "co"),
   208→        ("crush", "cs"),
   209→        ("aider", "ai"),
   210→    ];
   211→
   212→    for (suffix, label) in known_suffixes {
   213→        if slug.ends_with(suffix) || slug.contains(&format!("-{}", suffix)) {
   214→            return label.to_string();
   215→        }
   216→    }
   217→
   218→    slug.chars().take(2).collect()
   219→}
