   540→    fn open_control_session(&self) -> Result<()> {
   541→        if inside_zellij() {
   542→            self.zellij_action(&["new-tab", "--name", "dellij", "--cwd", self.project_root.as_str()])?;
   543→            return Ok(());
   544→        }
   545→
   546→        let session = self.session_name();
   547→        if self.session_exists(&session)? {
   548→            self.zellij(&["attach", &session])?;
   549→        } else {
   550→            self.zellij(&["--session", &session])?;
   551→        }
   552→        Ok(())
   553→    }
