   555→    fn open_workspace(&mut self, slug: &str) -> Result<()> {
   556→        let workspace = self.workspace(slug)?.clone();
   557→        self.open_control_session_if_needed()?;
   558→        self.open_workspace_tab(&workspace)
   559→    }
   560→
   561→    fn open_control_session_if_needed(&self) -> Result<()> {
   562→        if inside_zellij() {
   563→            return Ok(());
   564→        }
   565→        let session = self.session_name();
   566→        if !self.session_exists(&session)? {
   567→            self.zellij(&["--session", &session, "--new-session-with-layout", "default"])?;
   568→        }
   569→        Ok(())
   570→    }
   571→
   572→    fn open_workspace_tab(&self, workspace: &Workspace) -> Result<()> {
   573→        let layout_path = self.write_layout_file(workspace)?;
   574→        if inside_zellij() {
   575→            self.zellij_action(&["new-tab", "--layout", layout_path.as_str(), "--name", &workspace.slug])?;
   576→            return Ok(());
   577→        }
   578→
   579→        let session = self.session_name();
   580→        if self.session_exists(&session)? {
   581→            self.zellij(&[
   582→                "action",
   583→                "--session",
   584→                &session,
   585→                "new-tab",
   586→                "--layout",
   587→                layout_path.as_str(),
   588→                "--name",
   589→                &workspace.slug,
   590→            ])?;
   591→            self.zellij(&["attach", &session])?;
   592→            return Ok(());
   593→        }
   594→
   595→        self.zellij(&[
   596→            "--session",
   597→            &session,
   598→            "--new-session-with-layout",
   599→            layout_path.as_str(),
   600→        ])?;
   601→        Ok(())
   602→    }
