   786→    let cwd = Utf8PathBuf::from_path_buf(cwd).map_err(|_| anyhow::anyhow!("cwd is not valid utf-8"))?;
   787→    if let Ok(root) = git_output(&cwd, &["rev-parse", "--show-toplevel"]) {
   788→        return Ok(Utf8PathBuf::from(root.trim()));
   789→    }
   790→    Ok(cwd)
