   838→fn slugify(input: &str, agent: &str) -> String {
   839→    let mut pieces = Vec::new();
   840→    let base = input
   841→        .chars()
   842→        .map(|ch| if ch.is_ascii_alphanumeric() { ch.to_ascii_lowercase() } else { '-' })
   843→        .collect::<String>();
   844→    for part in base.split('-').filter(|part| !part.is_empty()) {
   845→        pieces.push(part);
   846→        if pieces.len() == 6 {
   847→            break;
   848→        }
   849→    }
   850→    if pieces.is_empty() {
   851→        pieces.push("workspace");
   852→    }
   853→    format!("{}-{}", pieces.join("-"), agent)
   854→}
