   246→        let slug = slugify(args.name.as_deref().unwrap_or(&args.prompt), &agent);
   247→        if self.config.workspaces.iter().any(|w| w.slug == slug) {
   248→            bail!("workspace '{slug}' already exists");
   249→        }
   250→
   251→        let base_branch = match args.base_branch {
   252→            Some(branch) => branch,
   253→            None => detect_base_branch(&self.project_root)
   254→                .unwrap_or_else(|_| self.config.settings.base_branch.clone()),
   255→        };
   256→        let branch_name = format!("{}{}", self.config.settings.branch_prefix, slug);
   257→        let worktree_path = self.workspace_root().join(&slug);
   258→        fs::create_dir_all(self.workspace_root())
   259→            .with_context(|| format!("creating {}", self.workspace_root()))?;
   260→
   261→        git(
   262→            &self.project_root,
   263→            &[
   264→                "worktree",
   265→                "add",
   266→                "-b",
   267→                &branch_name,
   268→                worktree_path.as_str(),
   269→                &base_branch,
   270→            ],
   271→        )
   272→        .with_context(|| format!("creating git worktree for {slug}"))?;
   273→
   274→        let workspace = Workspace {
   275→            slug: slug.clone(),
   276→            prompt: args.prompt.clone(),
   277→            agent: agent.clone(),
   278→            branch_name,
   279→            base_branch,
   280→            worktree_path: worktree_path.clone(),
   281→            status: WorkspaceStatus::Working,
   282→            created_at: Utc::now(),
   283→            updated_at: Utc::now(),
   284→            ports: args.port,
   285→            urls: args.url,
   286→            last_command: Some(render_agent_command(&agent, &args.prompt)),
   287→            notes: Vec::new(),
   288→        };
   289→
   290→        self.write_status_file(&workspace)?;
   291→        self.write_layout_file(&workspace)?;
   292→        self.config.workspaces.push(workspace.clone());
   293→        self.save()?;
   294→
   295→        if args.setup {
   296→            self.run_hook("workspace_setup", &workspace)?;
   297→        }
   298→
   299→        println!("Created workspace {}", workspace.slug);
   300→        println!("  path: {}", workspace.worktree_path);
   301→        println!("  branch: {}", workspace.branch_name);
   302→        println!("  agent command: {}", workspace.last_command.as_deref().unwrap_or(""));
   303→        Ok(workspace)
   304→    }
