   391→    fn run_in_workspace(&self, args: RunArgs) -> Result<()> {
   392→        let workspace = self.workspace(&args.slug)?;
   393→        let command = self.resolve_bookmark_or_command(&args.target)?;
   394→
   395→        if inside_zellij() {
   396→            let mut zellij_args = vec!["run"];
   397→            if args.floating {
   398→                zellij_args.push("--floating");
   399→            }
   400→            if args.close_on_exit {
   401→                zellij_args.push("--close-on-exit");
   402→            }
   403→            zellij_args.extend_from_slice(&["--cwd", workspace.worktree_path.as_str(), "--name", &args.target]);
   404→            zellij_args.extend_from_slice(&["--", "bash", "-lc", &command]);
   405→            self.zellij(&zellij_args)?;
   406→        } else {
   407→            let status = Command::new("bash")
   408→                .args(["-lc", &command])
   409→                .current_dir(&workspace.worktree_path)
   410→                .status()
   411→                .with_context(|| format!("running command in {}", workspace.worktree_path))?;
   412→            if !status.success() {
   413→                bail!("command exited with {}", status);
   414→            }
   415→        }
   416→        Ok(())
   417→    }
