   654→    fn run_hook(&self, hook_name: &str, workspace: &Workspace) -> Result<()> {
   655→        let hook_path = self.state_dir.join("hooks").join(hook_name);
   656→        if !hook_path.exists() {
   657→            return Ok(());
   658→        }
   659→
   660→        let mut command = Command::new(&hook_path);
   661→        command.current_dir(&workspace.worktree_path);
   662→        command.env("DELLIJ_ROOT", self.project_root.as_str());
   663→        command.env("DELLIJ_STATE_DIR", self.state_dir.as_str());
   664→        command.env("DELLIJ_SLUG", &workspace.slug);
   665→        command.env("DELLIJ_AGENT", &workspace.agent);
   666→        command.env("DELLIJ_BRANCH", &workspace.branch_name);
   667→        command.env("DELLIJ_WORKTREE_PATH", workspace.worktree_path.as_str());
   668→        command.env("DELLIJ_PROMPT", &workspace.prompt);
   669→        let status = command
   670→            .status()
   671→            .with_context(|| format!("running hook {}", hook_path))?;
   672→        if !status.success() {
   673→            bail!("hook {} exited with {}", hook_path, status);
   674→        }
   675→        Ok(())
   676→    }
