   780→fn resolve_project_root(project_root: Option<Utf8PathBuf>) -> Result<Utf8PathBuf> {
   781→    if let Some(project_root) = project_root {
   782→        return Ok(project_root);
   783→    }
   784→
   785→    let cwd = env::current_dir().context("resolving current directory")?;
   786→    let cwd = Utf8PathBuf::from_path_buf(cwd).map_err(|_| anyhow::anyhow!("cwd is not valid utf-8"))?;
   787→    if let Ok(root) = git_output(&cwd, &["rev-parse", "--show-toplevel"]) {
   788→        return Ok(Utf8PathBuf::from(root.trim()));
   789→    }
   790→    Ok(cwd)
   791→}
   792→
   793→fn detect_base_branch(project_root: &Utf8Path) -> Result<String> {
   794→    let output = git_output(
   795→        project_root,
   796→        &["symbolic-ref", "refs/remotes/origin/HEAD", "--short"],
   797→    )?;
   798→    Ok(output.trim().trim_start_matches("origin/").to_string())
   799→}
   800→
   801→fn git(project_root: &Utf8Path, args: &[&str]) -> Result<()> {
   802→    let status = Command::new("git")
   803→        .args(args)
   804→        .current_dir(project_root)
   805→        .stdin(Stdio::null())
   806→        .status()
   807→        .with_context(|| format!("running git {}", args.join(" ")))?;
   808→    if !status.success() {
   809→        bail!("git {} exited with {}", args.join(" "), status);
   810→    }
   811→    Ok(())
   812→}
   813→
   814→fn git_output(project_root: &Utf8Path, args: &[&str]) -> Result<String> {
   815→    let output = Command::new("git")
   816→        .args(args)
   817→        .current_dir(project_root)
   818→        .stdin(Stdio::null())
   819→        .output()
   820→        .with_context(|| format!("running git {}", args.join(" ")))?;
   821→    if !output.status.success() {
   822→        bail!(
   823→            "git {} exited with {}: {}",
