        };

        Ok(Self {
            project_root,
            state_dir,
            config_path,
            config,
        })
    }

    fn run(&mut self, command: Commands) -> Result<()> {
        match command {
            Commands::Init => self.init(),
            Commands::Open(args) => self.open(args),
            Commands::New(args) => self.new_workspace(args),
            Commands::List => self.list(),
            Commands::Run(args) => self.run_in_workspace(args),
            Commands::Bookmark { command } => self.bookmark(command),
            Commands::Show(reference) => self.show(&reference.slug),
            Commands::Status(args) => self.update_status(args),
            Commands::Close(args) => self.close(args),
            Commands::Layout(reference) => self.print_layout(&reference.slug),
            Commands::Doctor => self.doctor(),
        }
    }

    fn init(&mut self) -> Result<()> {
        self.ensure_zellij_available()?;
        self.save()?;
        println!("Initialized dellij at {}", self.state_dir);
        println!("Workspaces root: {}", self.workspace_root());
        println!("Hooks dir: {}", self.state_dir.join("hooks"));
        println!("Session: {}", self.session_name());
        Ok(())
    }

    fn new_workspace(&mut self, args: NewArgs) -> Result<()> {
        self.ensure_zellij_available()?;
        let should_open = args.open;
        let workspace = self.new_workspace_from_args(args)?;
        if should_open {
            self.open_workspace_tab(&workspace)?;
        }
        Ok(())
    }

    fn open(&mut self, args: OpenArgs) -> Result<()> {
        self.ensure_zellij_available()?;

        if args.create {
            let prompt = args
                .prompt
                .clone()
                .with_context(|| "--create requires --prompt")?;
            let slug = {
                let new_args = NewArgs {
                    prompt,
                    name: args.name.clone(),
                    agent: args.agent.clone(),
                    base_branch: None,
                    port: args.port.clone(),
                    url: args.url.clone(),
                    setup: args.setup,
                    open: false,
                };
                self.new_workspace_from_args(new_args)?.slug
            };
            return self.open_workspace(&slug);
        }

        match args.slug {
            Some(slug) => self.open_workspace(&slug),
            None => self.open_control_session(),
        }
    }

    fn new_workspace_from_args(&mut self, args: NewArgs) -> Result<Workspace> {
        let agent = args
            .agent
            .unwrap_or_else(|| self.config.settings.default_agent.clone());
        let slug = slugify(args.name.as_deref().unwrap_or(&args.prompt), &agent);
        if self.config.workspaces.iter().any(|w| w.slug == slug) {
            bail!("workspace '{slug}' already exists");
        }

        let base_branch = match args.base_branch {
            Some(branch) => branch,
            None => detect_base_branch(&self.project_root)
                .unwrap_or_else(|_| self.config.settings.base_branch.clone()),
        };
        let branch_name = format!("{}{}", self.config.settings.branch_prefix, slug);
        let worktree_path = self.workspace_root().join(&slug);
        fs::create_dir_all(self.workspace_root())
            .with_context(|| format!("creating {}", self.workspace_root()))?;

        git(
            &self.project_root,
            &[
                "worktree",
                "add",
                "-b",
                &branch_name,
                worktree_path.as_str(),
                &base_branch,
            ],
        )
        .with_context(|| format!("creating git worktree for {slug}"))?;

        let workspace = Workspace {
            slug: slug.clone(),
            prompt: args.prompt.clone(),
            agent: agent.clone(),
            branch_name,
            base_branch,
            worktree_path: worktree_path.clone(),
            status: WorkspaceStatus::Working,
            created_at: Utc::now(),
            updated_at: Utc::now(),
            ports: args.port,
            urls: args.url,
            last_command: Some(render_agent_command(&agent, &args.prompt)),
            notes: Vec::new(),
