    }

    fn write_layout_file(&self, workspace: &Workspace) -> Result<Utf8PathBuf> {
        let path = self
            .state_dir
            .join("layouts")
            .join(format!("{}.kdl", workspace.slug));
        fs::write(&path, self.render_layout(workspace))
            .with_context(|| format!("writing {}", path))?;
        Ok(path)
    }

    fn render_layout(&self, workspace: &Workspace) -> String {
        format!(
            "layout {{\n  pane split_direction=\"vertical\" {{\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"{agent_cmd}\" }}\n    pane command=\"bash\" cwd=\"{cwd}\"\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"git status --short --branch\" }}\n  }}\n}}\n",
            cwd = workspace.worktree_path,
            agent_cmd = shell_escape(workspace.last_command.as_deref().unwrap_or("bash"))
        )
    }

    fn open_control_session(&self) -> Result<()> {
        if inside_zellij() {
            self.zellij_action(&["new-tab", "--name", "dellij", "--cwd", self.project_root.as_str()])?;
            return Ok(());
        }

        let session = self.session_name();
        if self.session_exists(&session)? {
            self.zellij(&["attach", &session])?;
        } else {
            self.zellij(&["--session", &session])?;
        }
        Ok(())
    }

    fn open_workspace(&mut self, slug: &str) -> Result<()> {
        let workspace = self.workspace(slug)?.clone();
        self.open_control_session_if_needed()?;
        self.open_workspace_tab(&workspace)
    }

    fn open_control_session_if_needed(&self) -> Result<()> {
        if inside_zellij() {
            return Ok(());
        }
        let session = self.session_name();
        if !self.session_exists(&session)? {
            self.zellij(&["--session", &session, "--new-session-with-layout", "default"])?;
        }
        Ok(())
    }

    fn open_workspace_tab(&self, workspace: &Workspace) -> Result<()> {
        let layout_path = self.write_layout_file(workspace)?;
        if inside_zellij() {
            self.zellij_action(&["new-tab", "--layout", layout_path.as_str(), "--name", &workspace.slug])?;
            return Ok(());
        }

        let session = self.session_name();
        if self.session_exists(&session)? {
            self.zellij(&[
                "action",
                "--session",
                &session,
                "new-tab",
                "--layout",
                layout_path.as_str(),
                "--name",
                &workspace.slug,
            ])?;
            self.zellij(&["attach", &session])?;
            return Ok(());
        }

        self.zellij(&[
            "--session",
            &session,
            "--new-session-with-layout",
            layout_path.as_str(),
        ])?;
        Ok(())
    }

    fn session_name(&self) -> String {
        format!("dellij-{}", slugify(self.project_root.as_str(), "session"))
    }

    fn resolve_bookmark_or_command(&self, target: &str) -> Result<String> {
        if let Some(bookmark) = self.config.bookmarks.iter().find(|bookmark| bookmark.name == target)
        {
            return Ok(bookmark.command.clone());
        }
        Ok(target.to_string())
    }

    fn session_exists(&self, session: &str) -> Result<bool> {
        let output = Command::new("zellij")
            .args(["list-sessions"])
            .current_dir(&self.project_root)
            .output()
            .context("listing zellij sessions")?;
        if !output.status.success() {
            bail!("zellij list-sessions failed");
        }
        let stdout = String::from_utf8(output.stdout)?;
        Ok(stdout.lines().any(|line| line.split_whitespace().next() == Some(session)))
    }

    fn zellij(&self, args: &[&str]) -> Result<()> {
        let status = Command::new("zellij")
            .args(args)
            .current_dir(&self.project_root)
            .status()
            .with_context(|| format!("running zellij {}", args.join(" ")))?;
        if !status.success() {
            bail!("zellij {} exited with {}", args.join(" "), status);
        }
        Ok(())
    }

    fn zellij_action(&self, args: &[&str]) -> Result<()> {
        let mut full_args = vec!["action"];
        full_args.extend_from_slice(args);
        self.zellij(&full_args)
    }

    fn ensure_zellij_available(&self) -> Result<()> {
        if command_exists("zellij") {
            return Ok(());
        }
        bail!("zellij is required but was not found on PATH");
    }

    fn run_hook(&self, hook_name: &str, workspace: &Workspace) -> Result<()> {
        let hook_path = self.state_dir.join("hooks").join(hook_name);
        if !hook_path.exists() {
            return Ok(());
        }

        let mut command = Command::new(&hook_path);
        command.current_dir(&workspace.worktree_path);
        command.env("DELLIJ_ROOT", self.project_root.as_str());
        command.env("DELLIJ_STATE_DIR", self.state_dir.as_str());
        command.env("DELLIJ_SLUG", &workspace.slug);
        command.env("DELLIJ_AGENT", &workspace.agent);
        command.env("DELLIJ_BRANCH", &workspace.branch_name);
        command.env("DELLIJ_WORKTREE_PATH", workspace.worktree_path.as_str());
        command.env("DELLIJ_PROMPT", &workspace.prompt);
        let status = command
            .status()
            .with_context(|| format!("running hook {}", hook_path))?;
        if !status.success() {
            bail!("hook {} exited with {}", hook_path, status);
        }
        Ok(())
    }

    fn save(&self) -> Result<()> {
        write_json(&self.config_path, &self.config)
    }
}

