   145→impl DellijStatusPlugin {
   146→    fn read_status_files(&self) -> Vec<AgentInfo> {
   147→        let status_dir = Path::new(&self.config_dir).join("status");
   148→
   149→        let read_dir = match fs::read_dir(&status_dir) {
   150→            Ok(rd) => rd,
