   162→            let slug = path
   163→                .file_stem()
   164→                .and_then(|s| s.to_str())
   165→                .unwrap_or("")
   166→                .to_string();
   167→
   168→            if slug.is_empty() {
   169→                continue;
   170→            }
   171→
   172→            let content = match fs::read_to_string(&path) {
   173→                Ok(c) => c,
   174→                Err(_) => continue,
   175→            };
   176→
   177→            let parsed: StatusFile = match serde_json::from_str(&content) {
   178→                Ok(p) => p,
   179→                Err(_) => continue,
