   196→fn derive_short_label(slug: &str) -> String {
   197→    let known_suffixes: &[(&str, &str)] = &[
   198→        ("claude-code", "cc"),
   199→        ("opencode", "oc"),
   200→        ("codex", "cx"),
   201→        ("cline", "cl"),
   202→        ("gemini", "gm"),
   203→        ("qwen", "qn"),
   204→        ("amp", "ap"),
