use std::collections::BTreeMap;
use std::env;
use std::fmt;
use std::fs;
use std::path::Path;
use std::process::{Command, Stdio};

use anyhow::{bail, Context, Result};
use camino::{Utf8Path, Utf8PathBuf};
use chrono::{DateTime, Utc};
use clap::{Args, Parser, Subcommand, ValueEnum};
use serde::{Deserialize, Serialize};

fn main() -> Result<()> {
    let cli = Cli::parse();
    let project_root = resolve_project_root(cli.project_root)?;
    let mut app = App::load_or_init(project_root)?;
    app.run(cli.command.unwrap_or(Commands::Open(OpenArgs::default())))
}

#[derive(Debug, Parser)]
#[command(name = "dellij")]
#[command(about = "Rust-first terminal workspace manager for Zellij")]
struct Cli {
    #[arg(long, global = true)]
    project_root: Option<Utf8PathBuf>,
    #[command(subcommand)]
    command: Option<Commands>,
}

#[derive(Debug, Subcommand)]
enum Commands {
    Init,
    Open(OpenArgs),
    New(NewArgs),
    List,
    Run(RunArgs),
    Bookmark {
        #[command(subcommand)]
        command: BookmarkCommand,
    },
    Show(WorkspaceRef),
    Status(StatusArgs),
    Close(CloseArgs),
    Layout(WorkspaceRef),
    Doctor,
}

#[derive(Debug, Args)]
struct NewArgs {
    prompt: String,
    #[arg(long)]
    name: Option<String>,
    #[arg(long)]
    agent: Option<String>,
    #[arg(long)]
    base_branch: Option<String>,
    #[arg(long)]
    port: Vec<u16>,
    #[arg(long)]
    url: Vec<String>,
    #[arg(long)]
    setup: bool,
    #[arg(long)]
    open: bool,
}

#[derive(Debug, Args, Default)]
struct OpenArgs {
    slug: Option<String>,
    #[arg(long)]
    create: bool,
    #[arg(long)]
    prompt: Option<String>,
    #[arg(long)]
    agent: Option<String>,
    #[arg(long)]
    name: Option<String>,
    #[arg(long)]
    port: Vec<u16>,
    #[arg(long)]
    url: Vec<String>,
    #[arg(long)]
    setup: bool,
}

#[derive(Debug, Args)]
struct WorkspaceRef {
    slug: String,
}

#[derive(Debug, Args)]
struct RunArgs {
    slug: String,
    target: String,
    #[arg(long)]
    floating: bool,
    #[arg(long)]
    close_on_exit: bool,
}

#[derive(Debug, Subcommand)]
enum BookmarkCommand {
    Add(BookmarkAddArgs),
    List,
    Remove(BookmarkRef),
}

#[derive(Debug, Args)]
struct BookmarkAddArgs {
    name: String,
    command: String,
    #[arg(long)]
    description: Option<String>,
}

#[derive(Debug, Args)]
struct BookmarkRef {
    name: String,
}

#[derive(Debug, Args)]
struct StatusArgs {
    slug: String,
    state: WorkspaceStatus,
    #[arg(long)]
    note: Option<String>,
}

#[derive(Debug, Args)]
struct CloseArgs {
    slug: String,
    #[arg(long)]
    keep_worktree: bool,
    #[arg(long)]
    teardown: bool,
}

#[derive(Debug)]
struct App {
    project_root: Utf8PathBuf,
    state_dir: Utf8PathBuf,
    config_path: Utf8PathBuf,
    config: Config,
}

impl App {
    fn load_or_init(project_root: Utf8PathBuf) -> Result<Self> {
        let state_dir = project_root.join(".dellij");
        fs::create_dir_all(state_dir.join("hooks"))
            .with_context(|| format!("creating {}", state_dir.join("hooks")))?;
        fs::create_dir_all(state_dir.join("status"))
            .with_context(|| format!("creating {}", state_dir.join("status")))?;
        fs::create_dir_all(state_dir.join("layouts"))
            .with_context(|| format!("creating {}", state_dir.join("layouts")))?;

        let config_path = state_dir.join("dellij.json");
        let config = if config_path.exists() {
            let raw = fs::read_to_string(&config_path)
                .with_context(|| format!("reading {}", config_path))?;
            serde_json::from_str(&raw).with_context(|| format!("parsing {}", config_path))?
        } else {
            let config = Config::new(project_root.clone());
            write_json(&config_path, &config)?;
            config
        };

        Ok(Self {
            project_root,
            state_dir,
            config_path,
            config,
        })
    }

    fn run(&mut self, command: Commands) -> Result<()> {
        match command {
            Commands::Init => self.init(),
            Commands::Open(args) => self.open(args),
            Commands::New(args) => self.new_workspace(args),
            Commands::List => self.list(),
            Commands::Run(args) => self.run_in_workspace(args),
            Commands::Bookmark { command } => self.bookmark(command),
            Commands::Show(reference) => self.show(&reference.slug),
            Commands::Status(args) => self.update_status(args),
            Commands::Close(args) => self.close(args),
            Commands::Layout(reference) => self.print_layout(&reference.slug),
            Commands::Doctor => self.doctor(),
        }
    }

    fn init(&mut self) -> Result<()> {
        self.ensure_zellij_available()?;
        self.save()?;
        println!("Initialized dellij at {}", self.state_dir);
        println!("Workspaces root: {}", self.workspace_root());
        println!("Hooks dir: {}", self.state_dir.join("hooks"));
        println!("Session: {}", self.session_name());
        Ok(())
    }

    fn new_workspace(&mut self, args: NewArgs) -> Result<()> {
        self.ensure_zellij_available()?;
        let should_open = args.open;
        let workspace = self.new_workspace_from_args(args)?;
        if should_open {
            self.open_workspace_tab(&workspace)?;
        }
        Ok(())
    }

    fn open(&mut self, args: OpenArgs) -> Result<()> {
        self.ensure_zellij_available()?;

        if args.create {
            let prompt = args
                .prompt
                .clone()
                .with_context(|| "--create requires --prompt")?;
            let slug = {
                let new_args = NewArgs {
                    prompt,
                    name: args.name.clone(),
                    agent: args.agent.clone(),
                    base_branch: None,
                    port: args.port.clone(),
                    url: args.url.clone(),
                    setup: args.setup,
                    open: false,
                };
                self.new_workspace_from_args(new_args)?.slug
            };
            return self.open_workspace(&slug);
        }

        match args.slug {
            Some(slug) => self.open_workspace(&slug),
            None => self.open_control_session(),
        }
    }

    fn new_workspace_from_args(&mut self, args: NewArgs) -> Result<Workspace> {
        let agent = args
            .agent
            .unwrap_or_else(|| self.config.settings.default_agent.clone());
        let slug = slugify(args.name.as_deref().unwrap_or(&args.prompt), &agent);
        if self.config.workspaces.iter().any(|w| w.slug == slug) {
            bail!("workspace '{slug}' already exists");
        }

        let base_branch = match args.base_branch {
            Some(branch) => branch,
            None => detect_base_branch(&self.project_root)
                .unwrap_or_else(|_| self.config.settings.base_branch.clone()),
        };
        let branch_name = format!("{}{}", self.config.settings.branch_prefix, slug);
        let worktree_path = self.workspace_root().join(&slug);
        fs::create_dir_all(self.workspace_root())
            .with_context(|| format!("creating {}", self.workspace_root()))?;

        git(
            &self.project_root,
            &[
                "worktree",
                "add",
                "-b",
                &branch_name,
                worktree_path.as_str(),
                &base_branch,
            ],
        )
        .with_context(|| format!("creating git worktree for {slug}"))?;

        let workspace = Workspace {
            slug: slug.clone(),
            prompt: args.prompt.clone(),
            agent: agent.clone(),
            branch_name,
            base_branch,
            worktree_path: worktree_path.clone(),
            status: WorkspaceStatus::Working,
            created_at: Utc::now(),
            updated_at: Utc::now(),
            ports: args.port,
            urls: args.url,
            last_command: Some(render_agent_command(&agent, &args.prompt)),
            notes: Vec::new(),
        };

        self.write_status_file(&workspace)?;
        self.write_layout_file(&workspace)?;
        self.config.workspaces.push(workspace.clone());
        self.save()?;

        if args.setup {
            self.run_hook("workspace_setup", &workspace)?;
        }

        println!("Created workspace {}", workspace.slug);
        println!("  path: {}", workspace.worktree_path);
        println!("  branch: {}", workspace.branch_name);
        println!("  agent command: {}", workspace.last_command.as_deref().unwrap_or(""));
        Ok(workspace)
    }

    fn list(&self) -> Result<()> {
        if self.config.workspaces.is_empty() {
            println!("No workspaces tracked for {}", self.project_root);
            return Ok(());
        }

        for workspace in &self.config.workspaces {
            let ports = if workspace.ports.is_empty() {
                String::from("-")
            } else {
                workspace
                    .ports
                    .iter()
                    .map(u16::to_string)
                    .collect::<Vec<_>>()
                    .join(",")
            };
            println!(
                "{:16} {:10} {:12} {:12} {}",
                workspace.slug,
                workspace.status,
                workspace.agent,
                ports,
                workspace.worktree_path
            );
        }
        Ok(())
    }

    fn show(&self, slug: &str) -> Result<()> {
        let workspace = self.workspace(slug)?;
        println!("{}", serde_json::to_string_pretty(workspace)?);
        Ok(())
    }

    fn bookmark(&mut self, command: BookmarkCommand) -> Result<()> {
        match command {
            BookmarkCommand::Add(args) => {
                self.config
                    .bookmarks
                    .retain(|bookmark| bookmark.name != args.name);
                self.config.bookmarks.push(Bookmark {
                    name: args.name,
                    command: args.command,
                    description: args.description,
                });
                self.config
                    .bookmarks
                    .sort_by(|left, right| left.name.cmp(&right.name));
                self.save()?;
                println!("Saved bookmark");
            }
            BookmarkCommand::List => {
                if self.config.bookmarks.is_empty() {
                    println!("No bookmarks saved");
                } else {
                    for bookmark in &self.config.bookmarks {
                        println!(
                            "{:16} {}{}",
                            bookmark.name,
                            bookmark.command,
                            bookmark
                                .description
                                .as_ref()
                                .map(|desc| format!("  # {desc}"))
                                .unwrap_or_default()
                        );
                    }
                }
            }
            BookmarkCommand::Remove(reference) => {
                let before = self.config.bookmarks.len();
                self.config
                    .bookmarks
                    .retain(|bookmark| bookmark.name != reference.name);
                if self.config.bookmarks.len() == before {
                    bail!("bookmark '{}' not found", reference.name);
                }
                self.save()?;
                println!("Removed bookmark {}", reference.name);
            }
        }
        Ok(())
    }

    fn run_in_workspace(&self, args: RunArgs) -> Result<()> {
        let workspace = self.workspace(&args.slug)?;
        let command = self.resolve_bookmark_or_command(&args.target)?;

        if inside_zellij() {
            let mut zellij_args = vec!["run"];
            if args.floating {
                zellij_args.push("--floating");
            }
            if args.close_on_exit {
                zellij_args.push("--close-on-exit");
            }
            zellij_args.extend_from_slice(&["--cwd", workspace.worktree_path.as_str(), "--name", &args.target]);
            zellij_args.extend_from_slice(&["--", "bash", "-lc", &command]);
            self.zellij(&zellij_args)?;
        } else {
            let status = Command::new("bash")
                .args(["-lc", &command])
                .current_dir(&workspace.worktree_path)
                .status()
                .with_context(|| format!("running command in {}", workspace.worktree_path))?;
            if !status.success() {
                bail!("command exited with {}", status);
            }
        }
        Ok(())
    }

    fn update_status(&mut self, args: StatusArgs) -> Result<()> {
        let workspace = self.workspace_mut(&args.slug)?;
        workspace.status = args.state;
        workspace.updated_at = Utc::now();
        if let Some(note) = args.note {
            workspace.notes.push(note);
        }
        let snapshot = workspace.clone();
        self.write_status_file(&snapshot)?;
        self.save()?;
        println!("{} -> {}", snapshot.slug, snapshot.status);
        Ok(())
    }

    fn close(&mut self, args: CloseArgs) -> Result<()> {
        let idx = self
            .config
            .workspaces
            .iter()
            .position(|w| w.slug == args.slug)
            .with_context(|| format!("workspace '{}' not found", args.slug))?;
        let workspace = self.config.workspaces[idx].clone();

        if args.teardown {
            self.run_hook("workspace_teardown", &workspace)?;
        }

        if !args.keep_worktree {
            git(
                &self.project_root,
                &["worktree", "remove", "--force", workspace.worktree_path.as_str()],
            )
            .with_context(|| format!("removing worktree {}", workspace.worktree_path))?;
        }

        let status_path = self.state_dir.join("status").join(format!("{}.json", workspace.slug));
        if status_path.exists() {
            fs::remove_file(&status_path).with_context(|| format!("removing {}", status_path))?;
        }

        self.config.workspaces.remove(idx);
        self.save()?;
        println!("Closed workspace {}", workspace.slug);
        Ok(())
    }

    fn print_layout(&self, slug: &str) -> Result<()> {
        let workspace = self.workspace(slug)?;
        let layout = self.render_layout(workspace);
        println!("{layout}");
        Ok(())
    }

    fn doctor(&self) -> Result<()> {
        let git_ok = command_exists("git");
        let zellij_ok = command_exists("zellij");
        let hooks_dir = self.state_dir.join("hooks");
        println!("project_root: {}", self.project_root);
        println!("session: {}", self.session_name());
        println!("git: {}", yes_no(git_ok));
        println!("zellij: {}", yes_no(zellij_ok));
        println!("hooks_dir: {}", yes_no(hooks_dir.exists()));
        println!("workspace_count: {}", self.config.workspaces.len());
        println!("bookmark_count: {}", self.config.bookmarks.len());
        Ok(())
    }

    fn workspace_root(&self) -> Utf8PathBuf {
        self.project_root.join(&self.config.settings.workspace_root)
    }

    fn workspace(&self, slug: &str) -> Result<&Workspace> {
        self.config
            .workspaces
            .iter()
            .find(|workspace| workspace.slug == slug)
            .with_context(|| format!("workspace '{slug}' not found"))
    }

    fn workspace_mut(&mut self, slug: &str) -> Result<&mut Workspace> {
        self.config
            .workspaces
            .iter_mut()
            .find(|workspace| workspace.slug == slug)
            .with_context(|| format!("workspace '{slug}' not found"))
    }

    fn write_status_file(&self, workspace: &Workspace) -> Result<()> {
        let status = StatusFile {
            slug: workspace.slug.clone(),
            status: workspace.status,
            updated_at: workspace.updated_at,
            agent: workspace.agent.clone(),
        };
        write_json(
            &self
                .state_dir
                .join("status")
                .join(format!("{}.json", workspace.slug)),
            &status,
        )
    }

    fn write_layout_file(&self, workspace: &Workspace) -> Result<Utf8PathBuf> {
        let path = self
            .state_dir
            .join("layouts")
            .join(format!("{}.kdl", workspace.slug));
        fs::write(&path, self.render_layout(workspace))
            .with_context(|| format!("writing {}", path))?;
        Ok(path)
    }

    fn render_layout(&self, workspace: &Workspace) -> String {
        format!(
            "layout {{\n  pane split_direction=\"vertical\" {{\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"{agent_cmd}\" }}\n    pane command=\"bash\" cwd=\"{cwd}\"\n    pane command=\"bash\" cwd=\"{cwd}\" {{ args \"-lc\" \"git status --short --branch\" }}\n  }}\n}}\n",
            cwd = workspace.worktree_path,
            agent_cmd = shell_escape(workspace.last_command.as_deref().unwrap_or("bash"))
        )
    }

    fn open_control_session(&self) -> Result<()> {
        if inside_zellij() {
            self.zellij_action(&["new-tab", "--name", "dellij", "--cwd", self.project_root.as_str()])?;
            return Ok(());
        }

        let session = self.session_name();
        if self.session_exists(&session)? {
            self.zellij(&["attach", &session])?;
        } else {
            self.zellij(&["--session", &session])?;
        }
        Ok(())
    }

    fn open_workspace(&mut self, slug: &str) -> Result<()> {
        let workspace = self.workspace(slug)?.clone();
        self.open_control_session_if_needed()?;
        self.open_workspace_tab(&workspace)
    }

    fn open_control_session_if_needed(&self) -> Result<()> {
        if inside_zellij() {
            return Ok(());
        }
        let session = self.session_name();
        if !self.session_exists(&session)? {
            self.zellij(&["--session", &session, "--new-session-with-layout", "default"])?;
        }
        Ok(())
    }

    fn open_workspace_tab(&self, workspace: &Workspace) -> Result<()> {
        let layout_path = self.write_layout_file(workspace)?;
        if inside_zellij() {
            self.zellij_action(&["new-tab", "--layout", layout_path.as_str(), "--name", &workspace.slug])?;
            return Ok(());
        }

        let session = self.session_name();
        if self.session_exists(&session)? {
            self.zellij(&[
                "action",
                "--session",
                &session,
                "new-tab",
                "--layout",
                layout_path.as_str(),
                "--name",
                &workspace.slug,
            ])?;
            self.zellij(&["attach", &session])?;
            return Ok(());
        }

        self.zellij(&[
            "--session",
            &session,
            "--new-session-with-layout",
            layout_path.as_str(),
        ])?;
        Ok(())
    }

    fn session_name(&self) -> String {
        format!("dellij-{}", slugify(self.project_root.as_str(), "session"))
    }

    fn resolve_bookmark_or_command(&self, target: &str) -> Result<String> {
        if let Some(bookmark) = self.config.bookmarks.iter().find(|bookmark| bookmark.name == target)
        {
            return Ok(bookmark.command.clone());
        }
        Ok(target.to_string())
    }

    fn session_exists(&self, session: &str) -> Result<bool> {
        let output = Command::new("zellij")
            .args(["list-sessions"])
            .current_dir(&self.project_root)
            .output()
            .context("listing zellij sessions")?;
        if !output.status.success() {
            bail!("zellij list-sessions failed");
        }
        let stdout = String::from_utf8(output.stdout)?;
        Ok(stdout.lines().any(|line| line.split_whitespace().next() == Some(session)))
    }

    fn zellij(&self, args: &[&str]) -> Result<()> {
        let status = Command::new("zellij")
            .args(args)
            .current_dir(&self.project_root)
            .status()
            .with_context(|| format!("running zellij {}", args.join(" ")))?;
        if !status.success() {
            bail!("zellij {} exited with {}", args.join(" "), status);
        }
        Ok(())
    }

    fn zellij_action(&self, args: &[&str]) -> Result<()> {
        let mut full_args = vec!["action"];
        full_args.extend_from_slice(args);
        self.zellij(&full_args)
    }

    fn ensure_zellij_available(&self) -> Result<()> {
        if command_exists("zellij") {
            return Ok(());
        }
        bail!("zellij is required but was not found on PATH");
    }

    fn run_hook(&self, hook_name: &str, workspace: &Workspace) -> Result<()> {
        let hook_path = self.state_dir.join("hooks").join(hook_name);
        if !hook_path.exists() {
            return Ok(());
        }

        let mut command = Command::new(&hook_path);
        command.current_dir(&workspace.worktree_path);
        command.env("DELLIJ_ROOT", self.project_root.as_str());
        command.env("DELLIJ_STATE_DIR", self.state_dir.as_str());
        command.env("DELLIJ_SLUG", &workspace.slug);
        command.env("DELLIJ_AGENT", &workspace.agent);
        command.env("DELLIJ_BRANCH", &workspace.branch_name);
        command.env("DELLIJ_WORKTREE_PATH", workspace.worktree_path.as_str());
        command.env("DELLIJ_PROMPT", &workspace.prompt);
        let status = command
            .status()
            .with_context(|| format!("running hook {}", hook_path))?;
        if !status.success() {
            bail!("hook {} exited with {}", hook_path, status);
        }
        Ok(())
    }

    fn save(&self) -> Result<()> {
        write_json(&self.config_path, &self.config)
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Config {
    project_root: Utf8PathBuf,
    created_at: DateTime<Utc>,
    settings: Settings,
    bookmarks: Vec<Bookmark>,
    workspaces: Vec<Workspace>,
}

impl Config {
    fn new(project_root: Utf8PathBuf) -> Self {
        Self {
            project_root,
            created_at: Utc::now(),
            settings: Settings::default(),
            bookmarks: Vec::new(),
            workspaces: Vec::new(),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Bookmark {
    name: String,
    command: String,
    description: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Settings {
    default_agent: String,
    base_branch: String,
    branch_prefix: String,
    workspace_root: Utf8PathBuf,
}

impl Default for Settings {
    fn default() -> Self {
        Self {
            default_agent: "codex".to_string(),
            base_branch: "main".to_string(),
            branch_prefix: "dellij/".to_string(),
            workspace_root: Utf8PathBuf::from(".dellij/workspaces"),
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct Workspace {
    slug: String,
    prompt: String,
    agent: String,
    branch_name: String,
    base_branch: String,
    worktree_path: Utf8PathBuf,
    status: WorkspaceStatus,
    created_at: DateTime<Utc>,
    updated_at: DateTime<Utc>,
    ports: Vec<u16>,
    urls: Vec<String>,
    last_command: Option<String>,
    notes: Vec<String>,
}

#[derive(Debug, Clone, Copy, Serialize, Deserialize, ValueEnum)]
#[serde(rename_all = "snake_case")]
enum WorkspaceStatus {
    Working,
    Waiting,
    Blocked,
    Review,
    Done,
    Error,
}

impl fmt::Display for WorkspaceStatus {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let label = match self {
            WorkspaceStatus::Working => "working",
            WorkspaceStatus::Waiting => "waiting",
            WorkspaceStatus::Blocked => "blocked",
            WorkspaceStatus::Review => "review",
            WorkspaceStatus::Done => "done",
            WorkspaceStatus::Error => "error",
        };
        f.write_str(label)
    }
}

#[derive(Debug, Clone, Serialize)]
struct StatusFile {
    slug: String,
    status: WorkspaceStatus,
    updated_at: DateTime<Utc>,
    agent: String,
}

fn resolve_project_root(project_root: Option<Utf8PathBuf>) -> Result<Utf8PathBuf> {
    if let Some(project_root) = project_root {
        return Ok(project_root);
    }

    let cwd = env::current_dir().context("resolving current directory")?;
    let cwd = Utf8PathBuf::from_path_buf(cwd).map_err(|_| anyhow::anyhow!("cwd is not valid utf-8"))?;
    if let Ok(root) = git_output(&cwd, &["rev-parse", "--show-toplevel"]) {
        return Ok(Utf8PathBuf::from(root.trim()));
    }
    Ok(cwd)
}

fn detect_base_branch(project_root: &Utf8Path) -> Result<String> {
    let output = git_output(
        project_root,
        &["symbolic-ref", "refs/remotes/origin/HEAD", "--short"],
    )?;
    Ok(output.trim().trim_start_matches("origin/").to_string())
}

fn git(project_root: &Utf8Path, args: &[&str]) -> Result<()> {
    let status = Command::new("git")
        .args(args)
        .current_dir(project_root)
        .stdin(Stdio::null())
        .status()
        .with_context(|| format!("running git {}", args.join(" ")))?;
    if !status.success() {
        bail!("git {} exited with {}", args.join(" "), status);
    }
    Ok(())
}

fn git_output(project_root: &Utf8Path, args: &[&str]) -> Result<String> {
    let output = Command::new("git")
        .args(args)
        .current_dir(project_root)
        .stdin(Stdio::null())
        .output()
        .with_context(|| format!("running git {}", args.join(" ")))?;
    if !output.status.success() {
        bail!(
            "git {} exited with {}: {}",
            args.join(" "),
            output.status,
            String::from_utf8_lossy(&output.stderr)
        );
    }
    Ok(String::from_utf8(output.stdout)?.trim().to_string())
}

fn write_json<T: Serialize>(path: &Utf8Path, value: &T) -> Result<()> {
    let body = serde_json::to_string_pretty(value)?;
    fs::write(path, body).with_context(|| format!("writing {}", path))?;
    Ok(())
}

fn slugify(input: &str, agent: &str) -> String {
    let mut pieces = Vec::new();
    let base = input
        .chars()
        .map(|ch| if ch.is_ascii_alphanumeric() { ch.to_ascii_lowercase() } else { '-' })
        .collect::<String>();
    for part in base.split('-').filter(|part| !part.is_empty()) {
        pieces.push(part);
        if pieces.len() == 6 {
            break;
        }
    }
    if pieces.is_empty() {
        pieces.push("workspace");
    }
    format!("{}-{}", pieces.join("-"), agent)
}

fn render_agent_command(agent: &str, prompt: &str) -> String {
    match agent {
        "codex" => format!("codex \"{}\"", shell_escape(prompt)),
        "claude" => format!("claude \"{}\"", shell_escape(prompt)),
        "aider" => format!("aider --message \"{}\"", shell_escape(prompt)),
        other => format!("{other} \"{}\"", shell_escape(prompt)),
    }
}

fn shell_escape(input: &str) -> String {
    input.replace('\\', "\\\\").replace('"', "\\\"")
}

fn command_exists(name: &str) -> bool {
    env::var_os("PATH")
        .and_then(|paths| {
            env::split_paths(&paths).find(|dir| {
                let candidate = dir.join(name);
                candidate.is_file() || is_windows_exe(&candidate)
            })
        })
        .is_some()
}

fn inside_zellij() -> bool {
    env::var_os("ZELLIJ").is_some()
}

fn is_windows_exe(candidate: &Path) -> bool {
    ["exe", "bat", "cmd"]
        .iter()
        .map(|ext| candidate.with_extension(ext))
        .any(|path| path.is_file())
}

fn yes_no(value: bool) -> &'static str {
    if value { "ok" } else { "missing" }
}

fn env_map(workspace: &Workspace, state_dir: &Utf8Path, project_root: &Utf8Path) -> BTreeMap<String, String> {
    BTreeMap::from([
        ("DELLIJ_ROOT".to_string(), project_root.to_string()),
        ("DELLIJ_STATE_DIR".to_string(), state_dir.to_string()),
        ("DELLIJ_SLUG".to_string(), workspace.slug.clone()),
        ("DELLIJ_AGENT".to_string(), workspace.agent.clone()),
        ("DELLIJ_BRANCH".to_string(), workspace.branch_name.clone()),
        (
            "DELLIJ_WORKTREE_PATH".to_string(),
            workspace.worktree_path.to_string(),
        ),
        ("DELLIJ_PROMPT".to_string(), workspace.prompt.clone()),
    ])
}

#[cfg(test)]
mod tests {
    use super::*;

    // ── helpers ──────────────────────────────────────────────────────────────

    fn make_workspace(slug: &str) -> Workspace {
        Workspace {
            slug: slug.to_string(),
            prompt: "fix the login bug".to_string(),
            agent: "codex".to_string(),
            branch_name: format!("dellij/{slug}"),
            base_branch: "main".to_string(),
            worktree_path: Utf8PathBuf::from(format!("/tmp/ws/{slug}")),
            status: WorkspaceStatus::Working,
            created_at: chrono::Utc::now(),
            updated_at: chrono::Utc::now(),
            ports: vec![3000, 8080],
            urls: vec!["http://localhost:3000".to_string()],
            last_command: Some("codex \"fix the login bug\"".to_string()),
            notes: vec!["initial note".to_string()],
        }
    }

    // ── slugify ───────────────────────────────────────────────────────────────

    mod slugify_unit {
        use super::*;

        #[test]
        fn basic_phrase() {
            assert_eq!(slugify("fix the login bug", "codex"), "fix-the-login-bug-codex");
        }

        #[test]
        fn all_non_alphanumeric_falls_back() {
            assert_eq!(slugify("!!!", "agent"), "workspace-agent");
            assert_eq!(slugify("", "agent"), "workspace-agent");
        }

        #[test]
        fn truncates_to_six_words() {
            assert_eq!(
                slugify("one two three four five six seven eight nine", "ag"),
                "one-two-three-four-five-six-ag"
            );
        }

        #[test]
        fn uppercase_is_lowercased() {
            assert_eq!(slugify("FIX THE BUG", "codex"), "fix-the-bug-codex");
        }

        #[test]
        fn repeated_separators_are_collapsed() {
            // "fix--bug" → split on '-' filters empty → ["fix","bug"]
            assert_eq!(slugify("fix--bug", "codex"), "fix-bug-codex");
        }

        #[test]
        fn agent_always_appended() {
            for agent in &["codex", "claude-code", "aider", "x"] {
                let slug = slugify("do something", agent);
                assert!(slug.ends_with(&format!("-{agent}")), "slug={slug}");
            }
        }
    }

    // ── shell_escape ─────────────────────────────────────────────────────────

    mod shell_escape_unit {
        use super::*;

        #[test]
        fn no_specials_unchanged() {
            assert_eq!(shell_escape("hello world"), "hello world");
        }

        #[test]
        fn double_quote_escaped() {
            assert_eq!(shell_escape(r#"say "hi""#), r#"say \"hi\""#);
        }

        #[test]
        fn backslash_escaped() {
            assert_eq!(shell_escape(r"a\b"), r"a\\b");
        }

        #[test]
        fn both_specials() {
            assert_eq!(shell_escape(r#"a\"b"#), r#"a\\\"b"#);
        }
    }

    // ── render_agent_command ──────────────────────────────────────────────────

    mod render_agent_command_unit {
        use super::*;

        #[test]
        fn codex_format() {
            assert_eq!(render_agent_command("codex", "fix bug"), r#"codex "fix bug""#);
        }

        #[test]
        fn claude_format() {
            assert_eq!(render_agent_command("claude", "fix bug"), r#"claude "fix bug""#);
        }

        #[test]
        fn aider_format() {
            assert_eq!(render_agent_command("aider", "fix bug"), r#"aider --message "fix bug""#);
        }

        #[test]
        fn unknown_agent_fallback() {
            assert_eq!(render_agent_command("mybot", "fix bug"), r#"mybot "fix bug""#);
        }

        #[test]
        fn prompt_with_quotes_is_escaped() {
            let cmd = render_agent_command("codex", r#"say "hello""#);
            // Should not contain bare double-quotes inside the argument
            assert!(cmd.contains(r#"\"hello\""#), "cmd={cmd}");
        }
    }

    // ── serde roundtrips ─────────────────────────────────────────────────────

    mod serde_roundtrips {
        use super::*;

        #[test]
        fn all_workspace_statuses_roundtrip() {
            let statuses = [
                WorkspaceStatus::Working,
                WorkspaceStatus::Waiting,
                WorkspaceStatus::Blocked,
                WorkspaceStatus::Review,
                WorkspaceStatus::Done,
                WorkspaceStatus::Error,
            ];
            for status in statuses {
                let json = serde_json::to_string(&status).unwrap();
                let restored: WorkspaceStatus = serde_json::from_str(&json).unwrap();
                assert_eq!(status.to_string(), restored.to_string());
            }
        }

        #[test]
        fn workspace_roundtrip_preserves_all_fields() {
            let original = make_workspace("login-fix-codex");
            let json = serde_json::to_string_pretty(&original).unwrap();
            let restored: Workspace = serde_json::from_str(&json).unwrap();
            assert_eq!(original.slug, restored.slug);
            assert_eq!(original.prompt, restored.prompt);
            assert_eq!(original.agent, restored.agent);
            assert_eq!(original.branch_name, restored.branch_name);
            assert_eq!(original.base_branch, restored.base_branch);
            assert_eq!(original.worktree_path, restored.worktree_path);
            assert_eq!(original.status.to_string(), restored.status.to_string());
            assert_eq!(original.ports, restored.ports);
            assert_eq!(original.urls, restored.urls);
            assert_eq!(original.notes, restored.notes);
        }

        #[test]
        fn config_roundtrip_preserves_workspaces_and_bookmarks() {
            let root = Utf8PathBuf::from("/tmp/test-project");
            let mut config = Config::new(root);
            config.bookmarks.push(Bookmark {
                name: "lint".to_string(),
                command: "cargo clippy".to_string(),
                description: Some("run clippy".to_string()),
            });
            config.workspaces.push(make_workspace("ws-a"));
            config.workspaces.push(make_workspace("ws-b"));

            let json = serde_json::to_string_pretty(&config).unwrap();
            let restored: Config = serde_json::from_str(&json).unwrap();
            assert_eq!(restored.bookmarks.len(), 1);
            assert_eq!(restored.workspaces.len(), 2);
            assert_eq!(restored.bookmarks[0].name, "lint");
        }

        #[test]
        fn status_file_serializes_without_worktree_path() {
            let sf = StatusFile {
                slug: "my-ws".to_string(),
                status: WorkspaceStatus::Blocked,
                updated_at: chrono::Utc::now(),
                agent: "claude".to_string(),
            };
            let json = serde_json::to_string(&sf).unwrap();
            assert!(json.contains("\"blocked\""));
            assert!(json.contains("\"my-ws\""));
        }
    }

    // ── business logic ────────────────────────────────────────────────────────

    mod business_logic {
        use super::*;

        #[test]
        fn bookmark_add_deduplicates_by_name() {
            let mut bookmarks = vec![
                Bookmark { name: "lint".to_string(), command: "old".to_string(), description: None },
                Bookmark { name: "test".to_string(), command: "cargo test".to_string(), description: None },
            ];
            // Simulate bookmark add: retain removes, then push
            bookmarks.retain(|b| b.name != "lint");
            bookmarks.push(Bookmark { name: "lint".to_string(), command: "new".to_string(), description: None });
            assert_eq!(bookmarks.len(), 2);
            let lint = bookmarks.iter().find(|b| b.name == "lint").unwrap();
            assert_eq!(lint.command, "new");
        }

        #[test]
        fn env_map_contains_all_seven_keys() {
            let ws = make_workspace("test-slug");
            let state = Utf8PathBuf::from("/tmp/.dellij");
            let root = Utf8PathBuf::from("/tmp/project");
            let map = env_map(&ws, &state, &root);
            let required = [
                "DELLIJ_ROOT", "DELLIJ_STATE_DIR", "DELLIJ_SLUG",
                "DELLIJ_AGENT", "DELLIJ_BRANCH", "DELLIJ_WORKTREE_PATH", "DELLIJ_PROMPT",
            ];
            for key in required {
                assert!(map.contains_key(key), "missing env key: {key}");
            }
            assert_eq!(map.len(), 7);
        }

        #[test]
        fn env_map_values_match_workspace_fields() {
            let ws = make_workspace("my-slug");
            let state = Utf8PathBuf::from("/s");
            let root = Utf8PathBuf::from("/r");
            let map = env_map(&ws, &state, &root);
            assert_eq!(map["DELLIJ_SLUG"], "my-slug");
            assert_eq!(map["DELLIJ_AGENT"], "codex");
            assert_eq!(map["DELLIJ_PROMPT"], "fix the login bug");
            assert_eq!(map["DELLIJ_ROOT"], "/r");
        }

        #[test]
        fn workspace_status_display_covers_all_variants() {
            assert_eq!(WorkspaceStatus::Working.to_string(), "working");
            assert_eq!(WorkspaceStatus::Waiting.to_string(), "waiting");
            assert_eq!(WorkspaceStatus::Blocked.to_string(), "blocked");
            assert_eq!(WorkspaceStatus::Review.to_string(), "review");
            assert_eq!(WorkspaceStatus::Done.to_string(), "done");
            assert_eq!(WorkspaceStatus::Error.to_string(), "error");
        }
    }

    // ── property tests ────────────────────────────────────────────────────────

    mod properties {
        use super::*;
        use proptest::prelude::*;

        proptest! {
            // slugify: output ends with -<agent>
            #[test]
            fn slugify_ends_with_agent(input in ".*", agent in "[a-z]+") {
                let result = slugify(&input, &agent);
                prop_assert!(
                    result.ends_with(&format!("-{agent}")),
                    "slug {result:?} does not end with -{agent}"
                );
            }

            // slugify: output charset is [a-z0-9-]
            #[test]
            fn slugify_output_charset(input in ".*", agent in "[a-z0-9]+") {
                let result = slugify(&input, &agent);
                prop_assert!(
                    result.chars().all(|c| c.is_ascii_lowercase() || c.is_ascii_digit() || c == '-'),
                    "slug {result:?} contains non-slug chars"
                );
            }

            // slugify: base (before -agent) is never empty
            #[test]
            fn slugify_base_never_empty(input in ".*", agent in "[a-z]+") {
                let result = slugify(&input, &agent);
                let suffix = format!("-{agent}");
                let base = result.strip_suffix(&suffix).unwrap_or(&result);
                prop_assert!(!base.is_empty(), "empty base in slug {result:?}");
            }

            // slugify: at most 6 word-segments in the base
            #[test]
            fn slugify_max_six_segments(input in ".*", agent in "[a-z]+") {
                let result = slugify(&input, &agent);
                let suffix = format!("-{agent}");
                let base = result.strip_suffix(&suffix).unwrap_or(&result);
                let count = base.split('-').filter(|s| !s.is_empty()).count();
                prop_assert!(count <= 6, "too many segments ({count}) in slug {result:?}");
            }

            // shell_escape: output forms a valid escape sequence stream —
            // every backslash must introduce \\ or \"
            #[test]
            fn shell_escape_only_valid_sequences(input in ".*") {
                let escaped = shell_escape(&input);
                let chars: Vec<char> = escaped.chars().collect();
                let mut i = 0;
                while i < chars.len() {
                    if chars[i] == '\\' {
                        prop_assert!(
                            i + 1 < chars.len() && (chars[i + 1] == '\\' || chars[i + 1] == '"'),
                            "bad escape at {i} in {escaped:?}"
                        );
                        i += 2;
                    } else {
                        prop_assert!(chars[i] != '"', "bare quote at {i} in {escaped:?}");
                        i += 1;
                    }
                }
            }

            // shell_escape: inputs with no specials pass through unchanged
            #[test]
            fn shell_escape_passthrough_for_safe_inputs(input in "[^\"\\\\]*") {
                prop_assert_eq!(shell_escape(&input), input);
            }

            // render_agent_command: output always contains the (escaped) prompt
            #[test]
            fn render_command_contains_prompt(agent in "[a-z]+", prompt in "[^\"\\\\]*") {
                let cmd = render_agent_command(&agent, &prompt);
                prop_assert!(
                    cmd.contains(&prompt),
                    "cmd {cmd:?} does not contain prompt {prompt:?}"
                );
            }

            // render_agent_command: output wraps prompt in double quotes
            #[test]
            fn render_command_wraps_prompt_in_quotes(agent in "[a-z]+", prompt in "[^\"\\\\]*") {
                let cmd = render_agent_command(&agent, &prompt);
                prop_assert!(
                    cmd.contains(&format!("\"{prompt}\"")),
                    "cmd {cmd:?} does not double-quote prompt {prompt:?}"
                );
            }

            // WorkspaceStatus: all variants survive a serde roundtrip
            #[test]
            fn workspace_status_serde_roundtrip(idx in 0usize..6) {
                let statuses = [
                    WorkspaceStatus::Working, WorkspaceStatus::Waiting,
                    WorkspaceStatus::Blocked, WorkspaceStatus::Review,
                    WorkspaceStatus::Done,    WorkspaceStatus::Error,
                ];
                let status = statuses[idx];
                let json = serde_json::to_string(&status).unwrap();
                let restored: WorkspaceStatus = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(status.to_string(), restored.to_string());
            }

            // Workspace serde roundtrip: slug and status preserved for arbitrary slugs
            #[test]
            fn workspace_serde_roundtrip_slug(slug in "[a-z][a-z0-9-]{0,30}") {
                let ws = make_workspace(&slug);
                let json = serde_json::to_string(&ws).unwrap();
                let restored: Workspace = serde_json::from_str(&json).unwrap();
                prop_assert_eq!(ws.slug, restored.slug);
                prop_assert_eq!(ws.ports, restored.ports);
                prop_assert_eq!(ws.notes, restored.notes);
            }
        }
    }
}

