fn status_to_color_idx(status: &str) -> usize {
    match status {
        "working" => 3, // Yellow
        "waiting" => 7, // Cyan
        "error" => 4,   // Red
        "blocked" => 4, // Red
        "review" => 7,  // Cyan
        "done" => 2,    // Green
        _ => 1,
    }
}

