//! Diff viewer: parses `git diff` output and renders it with syntax highlighting.
use gpui::*;
use similar::{ChangeTag, TextDiff};

use crate::app::AppModel;
use crate::colors;

pub struct DiffView {
    model: Model<AppModel>,
}

impl DiffView {
    pub fn new(model: Model<AppModel>, cx: &mut ViewContext<Self>) -> Self {
        cx.subscribe(&model, |_, _, _, cx| cx.notify()).detach();
        Self { model }
    }
}

/// A parsed line from `git diff` output.
#[derive(Clone, Debug)]
enum DiffLine {
    FileHeader(String),
    HunkHeader(String),
    Added(String),
    Removed(String),
    Context(String),
    NoNewline,
}

fn parse_diff(raw: &str) -> Vec<DiffLine> {
    raw.lines()
        .map(|line| {
            if line.starts_with("diff --git") || line.starts_with("+++") || line.starts_with("---")
                || line.starts_with("index ") || line.starts_with("new file")
                || line.starts_with("deleted file")
            {
                DiffLine::FileHeader(line.to_string())
            } else if line.starts_with("@@") {
                DiffLine::HunkHeader(line.to_string())
            } else if line.starts_with('+') {
                DiffLine::Added(line[1..].to_string())
            } else if line.starts_with('-') {
                DiffLine::Removed(line[1..].to_string())
            } else if line == "\\ No newline at end of file" {
                DiffLine::NoNewline
            } else {
                DiffLine::Context(
                    if line.starts_with(' ') { line[1..].to_string() } else { line.to_string() },
                )
            }
        })
        .collect()
}

fn render_diff_line(line: &DiffLine, line_num: usize) -> impl IntoElement {
    let (bg, text_color, prefix, content) = match line {
        DiffLine::FileHeader(s) => (
            colors::SURFACE1,
            colors::BLUE,
            "  ",
            s.clone(),
        ),
        DiffLine::HunkHeader(s) => (
            colors::MANTLE,
            colors::CYAN,
            "  ",
            s.clone(),
        ),
        DiffLine::Added(s) => (
            rgba(0xa6e3a120),
            colors::GREEN,
            "+ ",
            s.clone(),
        ),
        DiffLine::Removed(s) => (
            rgba(0xf38ba820),
            colors::RED,
            "- ",
            s.clone(),
        ),
        DiffLine::Context(s) => (
            colors::SURFACE0,
            colors::SUBTEXT0,
            "  ",
            s.clone(),
        ),
        DiffLine::NoNewline => (
            colors::SURFACE0,
            colors::OVERLAY0,
            "  ",
            "\\ No newline at end of file".to_string(),
        ),
    };

    div()
        .flex()
        .flex_row()
        .items_start()
        .w_full()
        .bg(bg)
        // Line number gutter
        .child(
            div()
                .w_12()
                .shrink_0()
                .text_color(colors::OVERLAY0)
                .text_xs()
                .px_2()
                .py_px()
                .font_family("monospace")
                .child(format!("{:4}", line_num)),
        )
        // Prefix (+/-/space)
        .child(
            div()
                .w_6()
                .shrink_0()
                .text_color(text_color)
                .text_xs()
                .py_px()
                .font_family("monospace")
                .child(prefix),
        )
        // Content
        .child(
            div()
                .flex_1()
                .text_color(text_color)
                .text_xs()
                .py_px()
                .font_family("monospace")
                .child(content),
        )
}

impl Render for DiffView {
    fn render(&mut self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let app = self.model.read(cx);
        let selected = app.selected_slug.clone();

        let (header, diff_lines): (String, Vec<DiffLine>) = match &selected {
            None => (
                "No workspace selected".to_string(),
                Vec::new(),
            ),
            Some(slug) => {
                let ws = app.workspaces().iter().find(|w| &w.slug == slug);
                let header = ws
                    .map(|w| format!("{} — {} → {}", w.slug, w.base_branch, w.branch_name))
                    .unwrap_or_default();
                let raw = app.diff_cache.get(slug).map(String::as_str).unwrap_or("");
                let lines = if raw.is_empty() {
                    vec![]
                } else {
                    parse_diff(raw)
                };
                (header, lines)
            }
        };

        let is_empty = diff_lines.is_empty();

        div()
            .flex()
            .flex_col()
            .w_full()
            .h_full()
            .bg(colors::SURFACE0)
            // Header bar
            .child(
                div()
                    .flex()
                    .flex_row()
                    .items_center()
                    .justify_between()
                    .px_4()
                    .py_3()
                    .border_b_1()
                    .border_color(colors::SURFACE1)
                    .child(
                        div()
                            .text_color(colors::TEXT)
                            .text_sm()
                            .font_bold()
                            .child(header),
                    ),
            )
            // Diff content
            .child(
                div()
                    .flex_1()
                    .overflow_y_scroll()
                    .when(is_empty, |d| {
                        d.flex()
                            .items_center()
                            .justify_center()
                            .child(
                                div()
                                    .text_color(colors::OVERLAY0)
                                    .text_sm()
                                    .child(if selected.is_none() {
                                        "Select a workspace in the sidebar."
                                    } else {
                                        "No diff — workspace is in sync with base branch."
                                    }),
                            )
                    })
                    .when(!is_empty, |d| {
                        d.children(
                            diff_lines
                                .iter()
                                .enumerate()
                                .map(|(i, line)| render_diff_line(line, i + 1)),
                        )
                    }),
            )
    }
}

