    prompt: String,
    #[arg(long)]
    name: Option<String>,
    #[arg(long)]
    agent: Option<String>,
    #[arg(long)]
    base_branch: Option<String>,
    /// Use an existing branch instead of creating a new one
    #[arg(long)]
    use_branch: Option<String>,
    /// Create worktree from the branch of a GitHub PR (requires gh CLI)
    #[arg(long)]
    base_pr: Option<u32>,
    #[arg(long)]
    port: Vec<u16>,
    #[arg(long)]
    url: Vec<String>,
    /// Named layout (default, minimal, full, agent-only, or a custom name from settings.layouts)
    #[arg(long)]
    layout: Option<String>,
    #[arg(long)]
    setup: bool,
    #[arg(long)]
    open: bool,
}

#[derive(Debug, Args, Default)]
struct OpenArgs {
    slug: Option<String>,
    #[arg(long)]
    create: bool,
    #[arg(long)]
    prompt: Option<String>,
    #[arg(long)]
    agent: Option<String>,
    #[arg(long)]
    name: Option<String>,
    #[arg(long)]
