//! Left sidebar: workspace list with status, branch, ahead/behind, ports, PR.
use gpui::*;

use dellij_core::{ahead_behind, Workspace, WorkspaceStatus};

use crate::app::{AppModel, Panel};
use crate::browser::launch_browser_window;
use crate::colors;

pub struct SidebarView {
    model: Model<AppModel>,
}

impl SidebarView {
    pub fn new(model: Model<AppModel>, cx: &mut ViewContext<Self>) -> Self {
        cx.subscribe(&model, |_, _, _, cx| cx.notify()).detach();
        Self { model }
    }

    fn render_header(&self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let attn = self.model.read(cx).attention_count();
        let attn_badge = if attn > 0 {
            div()
                .px_2()
                .py_px()
                .rounded_full()
                .bg(colors::RED)
                .text_color(colors::BASE)
                .text_xs()
                .child(format!("{attn}"))
        } else {
            div().hidden()
        };

        div()
            .flex()
            .flex_row()
            .items_center()
            .justify_between()
            .px_4()
            .py_3()
            .border_b_1()
            .border_color(colors::SURFACE1)
            .child(
                div()
                    .text_color(colors::MAUVE)
                    .font_bold()
                    .text_base()
                    .child("dellij"),
            )
            .child(attn_badge)
    }

    fn render_workspace(
        &self,
        ws: &Workspace,
        selected: bool,
        cx: &mut ViewContext<Self>,
    ) -> impl IntoElement {
        let slug = ws.slug.clone();
        let model = self.model.clone();
        let model2 = self.model.clone();

        let project_root = self.model.read(cx).project_root.clone();
        let ab = ahead_behind(&project_root, &ws.branch_name, &ws.base_branch)
            .map(|a| a.to_string())
            .unwrap_or_default();

        let status_color = colors::status_color(ws.status);
        let dot = colors::status_dot(ws.status);

        let ports_str = if ws.ports.is_empty() {
            String::new()
        } else {
            ws.ports.iter().map(|p| format!(":{p}")).collect::<Vec<_>>().join(" ")
        };

        let pr_str = ws.pr_number.map(|n| format!("PR#{n}")).unwrap_or_default();
        let attn_prefix = if ws.status.needs_attention() { "! " } else { "" };

        // URL for browser launch (first URL or first port)
        let launch_url = ws.urls.first().cloned().or_else(|| {
            ws.ports.first().map(|p| format!("http://localhost:{p}"))
        });

        div()
            .flex()
            .flex_col()
            .px_3()
            .py_2()
            .gap_1()
            .cursor_pointer()
            .rounded_md()
            .mx_1()
            .bg(if selected { colors::SURFACE0 } else { colors::MANTLE })
            .hover(|s| s.bg(colors::SURFACE0))
            .on_click(cx.listener(move |_, _, cx| {
                model.update(cx, |m, cx| m.select(slug.clone(), cx));
            }))
            // Top row: dot + slug + attention
            .child(
                div()
                    .flex()
                    .flex_row()
                    .items_center()
                    .gap_2()
                    .child(
                        div()
                            .text_color(status_color)
                            .text_sm()
                            .child(dot),
                    )
                    .child(
                        div()
                            .text_color(if selected { colors::TEXT } else { colors::SUBTEXT0 })
                            .text_sm()
                            .font_bold()
                            .child(format!("{attn_prefix}{}", ws.slug)),
                    ),
            )
            // Branch + ahead/behind
            .child(
                div()
                    .flex()
                    .flex_row()
                    .items_center()
                    .gap_2()
                    .pl_5()
                    .child(
                        div()
                            .text_color(colors::OVERLAY0)
                            .text_xs()
                            .child(ws.branch_name.trim_start_matches("dellij/").to_string()),
                    )
                    .when(!ab.is_empty(), |d| {
                        d.child(
                            div()
                                .text_color(colors::BLUE)
                                .text_xs()
                                .child(ab),
                        )
                    }),
            )
            // Meta row: ports, PR, agent
            .when(!ports_str.is_empty() || !pr_str.is_empty(), |d| {
                d.child(
                    div()
                        .flex()
                        .flex_row()
                        .gap_2()
                        .pl_5()
                        .when(!ports_str.is_empty(), |d| {
                            d.child(
                                div()
                                    .text_color(colors::CYAN)
                                    .text_xs()
                                    .child(ports_str.clone()),
                            )
                        })
                        .when(!pr_str.is_empty(), |d| {
                            d.child(
                                div()
                                    .text_color(colors::PEACH)
                                    .text_xs()
                                    .child(pr_str),
                            )
                        }),
                )
            })
            // Action buttons row (visible on hover via selected)
            .when(selected, |d| {
                d.child(
                    div()
                        .flex()
                        .flex_row()
                        .gap_1()
                        .pl_5()
                        .pt_1()
                        // Open in VS Code
                        .child(render_action_btn("VS Code", {
                            let slug2 = ws.slug.clone();
                            let m = model2.clone();
                            move |cx: &mut WindowContext| {
                                let _ = m.read(cx).open_in_editor(&slug2, "code");
                            }
                        }, cx))
                        // Open in Cursor
                        .child(render_action_btn("Cursor", {
                            let slug2 = ws.slug.clone();
                            let m = model2.clone();
                            move |cx: &mut WindowContext| {
                                let _ = m.read(cx).open_in_editor(&slug2, "cursor");
                            }
                        }, cx))
                        // Open in Zed
                        .child(render_action_btn("Zed", {
                            let slug2 = ws.slug.clone();
                            let m = model2.clone();
                            move |cx: &mut WindowContext| {
                                let _ = m.read(cx).open_in_editor(&slug2, "zed");
                            }
                        }, cx))
                        // Open browser (if URL/port available)
                        .when(launch_url.is_some(), |d| {
                            let url = launch_url.clone().unwrap();
                            d.child(render_action_btn("Browser", move |_cx| {
                                launch_browser_window(&url);
                            }, cx))
                        }),
                )
            })
    }
}

fn render_action_btn(
    label: &'static str,
    handler: impl Fn(&mut WindowContext) + 'static,
    cx: &mut ViewContext<SidebarView>,
) -> impl IntoElement {
    div()
        .px_2()
        .py_px()
        .rounded_sm()
        .bg(colors::SURFACE1)
        .text_color(colors::SUBTEXT0)
        .text_xs()
        .cursor_pointer()
        .hover(|s| s.bg(colors::SURFACE2).text_color(colors::TEXT))
        .on_click(move |_, cx| handler(cx))
        .child(label)
}

impl Render for SidebarView {
    fn render(&mut self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let selected = self.model.read(cx).selected_slug.clone();
        let workspaces: Vec<Workspace> = self.model.read(cx).workspaces().to_vec();

        div()
            .flex()
            .flex_col()
            .w_full()
            .h_full()
            .child(self.render_header(cx))
            .child(
                div()
                    .flex_1()
                    .overflow_y_scroll()
                    .py_2()
                    .flex()
                    .flex_col()
                    .gap_1()
                    .children(workspaces.iter().map(|ws| {
                        let is_selected = selected.as_deref() == Some(&ws.slug);
                        self.render_workspace(ws, is_selected, cx)
                    })),
            )
            .when(workspaces.is_empty(), |d| {
                d.child(
                    div()
                        .flex()
                        .flex_1()
                        .items_center()
                        .justify_center()
                        .text_color(colors::OVERLAY0)
                        .text_sm()
                        .child("No workspaces. Run `dellij new` to create one."),
                )
            })
    }
}

