     9→
    10→use crate::colors;
    11→use crate::diff_view::DiffView;
    12→use crate::notifications::NotificationView;
    13→use crate::sidebar::SidebarView;
    14→use crate::watcher::StatusWatcher;
    15→
    16→// ── Panel selection ───────────────────────────────────────────────────────────
    17→
    18→#[derive(Clone, Copy, PartialEq, Eq, Debug)]
    19→pub enum Panel {
    20→    Diff,
    21→    Notifications,
    22→    Browser,
    23→}
    24→
    25→// ── AppModel (reactive state) ─────────────────────────────────────────────────
    26→
    27→pub struct AppModel {
    28→    pub project_root: Utf8PathBuf,
    29→    pub config: Option<Config>,
    30→    pub selected_slug: Option<String>,
    31→    pub active_panel: Panel,
    32→    /// Diff text cache: slug → raw `git diff` output
    33→    pub diff_cache: std::collections::HashMap<String, String>,
    34→    _watcher: Option<StatusWatcher>,
    35→}
    36→
    37→impl AppModel {
    38→    pub fn new(project_root: Utf8PathBuf, cx: &mut ModelContext<Self>) -> Self {
    39→        let config = Self::load_config(&project_root);
    40→        let state_dir = project_root.join(".dellij");
    41→        let status_dir = state_dir.join("status");
    42→
    43→        // Set up file watcher to reload on status changes
    44→        let handle = cx.handle();
    45→        let watcher = StatusWatcher::spawn(&status_dir, {
    46→            let project_root = project_root.clone();
    47→            move || {
    48→                // Notify GPUI to re-run update on next cycle
    49→                // We can't directly call cx here (different thread), so we use
    50→                // a background spawn that then updates the model.
    51→                let _ = project_root.clone(); // keep alive
    52→                // In a real GPUI app you'd use cx.background_executor() or a channel.
    53→                // For now, the 2-second timer in the view will pick it up.
    54→                drop(handle.clone()); // reference handle to keep watcher alive
    55→            }
    56→        }).ok();
    57→
    58→        let mut model = Self {
    59→            project_root,
    60→            config,
    61→            selected_slug: None,
    62→            active_panel: Panel::Diff,
    63→            diff_cache: Default::default(),
    64→            _watcher: watcher,
    65→        };
    66→
    67→        // Pre-select the first workspace
    68→        if let Some(first) = model
    69→            .config
    70→            .as_ref()
    71→            .and_then(|c| c.workspaces.first())
    72→            .map(|w| w.slug.clone())
    73→        {
    74→            model.selected_slug = Some(first);
    75→        }
    76→
    77→        model
    78→    }
    79→
    80→    pub fn reload(&mut self, cx: &mut ModelContext<Self>) {
    81→        self.config = Self::load_config(&self.project_root);
    82→        self.diff_cache.clear();
    83→        cx.notify();
    84→    }
    85→
    86→    pub fn select(&mut self, slug: String, cx: &mut ModelContext<Self>) {
    87→        self.selected_slug = Some(slug.clone());
    88→        // Populate diff cache for the selected workspace
    89→        if !self.diff_cache.contains_key(&slug) {
    90→            if let Some(ws) = self.selected_workspace() {
    91→                let diff = dellij_core::git::workspace_diff(
    92→                    &self.project_root,
    93→                    &ws.base_branch,
    94→                    &ws.branch_name,
    95→                )
    96→                .unwrap_or_default();
    97→                self.diff_cache.insert(slug, diff);
    98→            }
    99→        }
   100→        cx.notify();
   101→    }
   102→
   103→    pub fn set_panel(&mut self, panel: Panel, cx: &mut ModelContext<Self>) {
   104→        self.active_panel = panel;
   105→        cx.notify();
   106→    }
   107→
   108→    pub fn selected_workspace(&self) -> Option<&Workspace> {
   109→        let slug = self.selected_slug.as_ref()?;
   110→        self.config
   111→            .as_ref()?
   112→            .workspaces
   113→            .iter()
   114→            .find(|w| &w.slug == slug)
   115→    }
   116→
   117→    pub fn workspaces(&self) -> &[Workspace] {
   118→        self.config
   119→            .as_ref()
   120→            .map(|c| c.workspaces.as_slice())
   121→            .unwrap_or(&[])
   122→    }
   123→
