//! Root application model and top-level view.
use std::fs;
use std::sync::Arc;

use camino::Utf8PathBuf;
use gpui::*;

use dellij_core::{ahead_behind, Config, Workspace, WorkspaceStatus};

use crate::colors;
use crate::diff_view::DiffView;
use crate::notifications::NotificationView;
use crate::sidebar::SidebarView;
use crate::watcher::StatusWatcher;

// ── Panel selection ───────────────────────────────────────────────────────────

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum Panel {
    Diff,
    Notifications,
    Browser,
}

// ── AppModel (reactive state) ─────────────────────────────────────────────────

pub struct AppModel {
    pub project_root: Utf8PathBuf,
    pub config: Option<Config>,
    pub selected_slug: Option<String>,
    pub active_panel: Panel,
    /// Diff text cache: slug → raw `git diff` output
    pub diff_cache: std::collections::HashMap<String, String>,
    _watcher: Option<StatusWatcher>,
}

impl AppModel {
    pub fn new(project_root: Utf8PathBuf, cx: &mut ModelContext<Self>) -> Self {
        let config = Self::load_config(&project_root);
        let state_dir = project_root.join(".dellij");
        let status_dir = state_dir.join("status");

        // Set up file watcher to reload on status changes
        let handle = cx.handle();
        let watcher = StatusWatcher::spawn(&status_dir, {
            let project_root = project_root.clone();
            move || {
                // Notify GPUI to re-run update on next cycle
                // We can't directly call cx here (different thread), so we use
                // a background spawn that then updates the model.
                let _ = project_root.clone(); // keep alive
                // In a real GPUI app you'd use cx.background_executor() or a channel.
                // For now, the 2-second timer in the view will pick it up.
                drop(handle.clone()); // reference handle to keep watcher alive
            }
        }).ok();

        let mut model = Self {
            project_root,
            config,
            selected_slug: None,
            active_panel: Panel::Diff,
            diff_cache: Default::default(),
            _watcher: watcher,
        };

        // Pre-select the first workspace
        if let Some(first) = model
            .config
            .as_ref()
            .and_then(|c| c.workspaces.first())
            .map(|w| w.slug.clone())
        {
            model.selected_slug = Some(first);
        }

        model
    }

    pub fn reload(&mut self, cx: &mut ModelContext<Self>) {
        self.config = Self::load_config(&self.project_root);
        self.diff_cache.clear();
        cx.notify();
    }

    pub fn select(&mut self, slug: String, cx: &mut ModelContext<Self>) {
        self.selected_slug = Some(slug.clone());
        // Populate diff cache for the selected workspace
        if !self.diff_cache.contains_key(&slug) {
            if let Some(ws) = self.selected_workspace() {
                let diff = dellij_core::git::workspace_diff(
                    &self.project_root,
                    &ws.base_branch,
                    &ws.branch_name,
                )
                .unwrap_or_default();
                self.diff_cache.insert(slug, diff);
            }
        }
        cx.notify();
    }

    pub fn set_panel(&mut self, panel: Panel, cx: &mut ModelContext<Self>) {
        self.active_panel = panel;
        cx.notify();
    }

    pub fn selected_workspace(&self) -> Option<&Workspace> {
        let slug = self.selected_slug.as_ref()?;
        self.config
            .as_ref()?
            .workspaces
            .iter()
            .find(|w| &w.slug == slug)
    }

    pub fn workspaces(&self) -> &[Workspace] {
        self.config
            .as_ref()
            .map(|c| c.workspaces.as_slice())
            .unwrap_or(&[])
    }

    pub fn attention_count(&self) -> usize {
        self.workspaces()
            .iter()
            .filter(|w| w.status.needs_attention())
            .count()
    }

    pub fn open_in_editor(&self, slug: &str, editor: &str) -> anyhow::Result<()> {
        if let Some(ws) = self.config.as_ref()
            .and_then(|c| c.workspaces.iter().find(|w| w.slug == slug))
        {
            dellij_core::git::open_in_editor(editor, &ws.worktree_path)?;
        }
        Ok(())
    }

    fn load_config(project_root: &Utf8PathBuf) -> Option<Config> {
        let path = project_root.join(".dellij/dellij.json");
        let raw = fs::read_to_string(&path).ok()?;
        serde_json::from_str(&raw).ok()
    }
}

// ── RootView ──────────────────────────────────────────────────────────────────

pub struct RootView {
    model: Model<AppModel>,
    sidebar: View<SidebarView>,
    diff: View<DiffView>,
    notifications: View<NotificationView>,
}

impl RootView {
    pub fn new(model: Model<AppModel>, cx: &mut ViewContext<Self>) -> Self {
        let sidebar = cx.new_view(|cx| SidebarView::new(model.clone(), cx));
        let diff = cx.new_view(|cx| DiffView::new(model.clone(), cx));
        let notifications = cx.new_view(|cx| NotificationView::new(model.clone(), cx));

        // Subscribe to model changes so the root view re-renders
        cx.subscribe(&model, |this, _, _, cx| {
            cx.notify();
        })
        .detach();

        Self { model, sidebar, diff, notifications }
    }

    fn render_tab_bar(&self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let panel = self.model.read(cx).active_panel;

        let tab = |label: &'static str, p: Panel, cx: &mut ViewContext<Self>| {
            let model = self.model.clone();
            let active = panel == p;
            div()
                .px_4()
                .py_2()
                .cursor_pointer()
                .rounded_t_md()
                .text_color(if active { colors::TEXT } else { colors::SUBTEXT0 })
                .bg(if active { colors::SURFACE0 } else { colors::MANTLE })
                .hover(|s| s.bg(colors::SURFACE0).text_color(colors::TEXT))
                .on_click(cx.listener(move |_, _, cx| {
                    model.update(cx, |m, cx| m.set_panel(p, cx));
                }))
                .child(label)
        };

        div()
            .flex()
            .flex_row()
            .gap_1()
            .px_2()
            .pt_2()
            .bg(colors::MANTLE)
            .child(tab("Diff", Panel::Diff, cx))
            .child(tab("Notifications", Panel::Notifications, cx))
            .child(tab("Browser", Panel::Browser, cx))
    }

    fn render_main_panel(&self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        let panel = self.model.read(cx).active_panel;

        let content: AnyView = match panel {
            Panel::Diff => self.diff.clone().into(),
            Panel::Notifications => self.notifications.clone().into(),
            Panel::Browser => {
                // Browser is an OS-level wry window; show a launch prompt here
                cx.new_view(|_| BrowserPrompt).into()
            }
        };

        div()
            .flex_1()
            .bg(colors::SURFACE0)
            .overflow_hidden()
            .child(content)
    }
}

impl Render for RootView {
    fn render(&mut self, cx: &mut ViewContext<Self>) -> impl IntoElement {
        div()
            .flex()
            .flex_row()
            .w_full()
            .h_full()
            .bg(colors::BASE)
            .text_color(colors::TEXT)
            // Sidebar (fixed width)
            .child(
                div()
                    .w_64()
                    .h_full()
                    .bg(colors::MANTLE)
                    .border_r_1()
                    .border_color(colors::SURFACE1)
                    .child(self.sidebar.clone()),
            )
            // Main area
            .child(
                div()
                    .flex_1()
                    .flex()
                    .flex_col()
                    .h_full()
                    .child(self.render_tab_bar(cx))
                    .child(self.render_main_panel(cx)),
            )
    }
}

// ── BrowserPrompt (placeholder for the browser tab) ──────────────────────────

struct BrowserPrompt;

impl Render for BrowserPrompt {
    fn render(&mut self, _cx: &mut ViewContext<Self>) -> impl IntoElement {
        div()
            .flex()
            .flex_col()
            .items_center()
            .justify_center()
            .w_full()
            .h_full()
            .gap_4()
            .child(
                div()
                    .text_color(colors::SUBTEXT0)
                    .text_xl()
                    .child("Browser"),
            )
            .child(
                div()
                    .text_color(colors::OVERLAY0)
                    .text_sm()
                    .child("Select a workspace URL in the sidebar to open the browser pane."),
            )
    }
}

