                                    .text_color(status_color)
                                    .text_xs()
                                    .child(status_icon),
                            ),
                    )
                    // ── row 2: branch + ahead/behind ──────────────────────────
                    .child(
                        div()
                            .flex()
                            .flex_row()
                            .items_center()
                            .gap_2()
                            .child(
                                div()
                                    .text_color(colors::OVERLAY0)
                                    .text_xs()
                                    .font_family("monospace")
                                    .overflow_hidden()
                                    .text_ellipsis()
                                    .child(branch_display),
                            )
                            .when(!ab.is_empty(), |d| {
                                d.child(
                                    div()
                                        .flex_shrink_0()
                                        .px(px(5.))
                                        .py_px()
                                        .rounded_full()
                                        .bg(rgba(0x89b4fa18))
                                        .text_color(colors::BLUE)
                                        .text_xs()
                                        .font_family("monospace")
                                        .child(ab),
                                )
                            }),
                    )
                    // ── row 3: ports + PR (only when present) ─────────────────
                    .when(!ports.is_empty() || pr_num.is_some(), |d| {
                        d.child(
                            div()
                                .flex()
                                .flex_row()
                                .items_center()
                                .gap(px(6.))
                                .children(ports.iter().map(|p| {
                                    div()
                                        .px(px(5.))
                                        .py_px()
                                        .rounded(px(4.))
                                        .bg(rgba(0x89dceb18))
                                        .text_color(colors::CYAN)
                                        .text_xs()
                                        .font_family("monospace")
                                        .child(format!(":{p}"))
                                }))
                                .when_some(pr_num, |d, n| {
                                    d.child(
                                        div()
                                            .px(px(5.))
                                            .py_px()
                                            .rounded(px(4.))
                                            .bg(rgba(0xfab38718))
                                            .text_color(colors::PEACH)
                                            .text_xs()
                                            .child(format!("PR #{n}")),
                                    )
                                })
                        )
                    })
                    // ── row 4: action buttons (selected only) ─────────────────
                    .when(selected, |d| {
                        d.child(
                            div()
                                .flex()
                                .flex_row()
                                .items_center()
                                .gap(px(4.))
                                .pt(px(4.))
                                .child(editor_btn("VS Code", {
                                    let slug = ws.slug.clone();
                                    let m = model_edit.clone();
                                    move |cx| { let _ = m.read(cx).open_in_editor(&slug, "code"); }
                                }, cx))
