                    w.slug,
                    w.base_branch,
                    w.branch_name.trim_start_matches("dellij/")
                )).unwrap_or_default();
                let raw   = app.diff_cache.get(slug).map(String::as_str).unwrap_or("");
                let lines = if raw.is_empty() { vec![] } else { parse_diff(raw) };
                (title, lines)
            }
        };

        let stats    = compute_stats(&diff_lines);
        let is_empty = diff_lines.is_empty();

        div()
            .flex()
            .flex_col()
            .w_full()
            .h_full()
            .bg(colors::BASE)
            // ── header ───────────────────────────────────────────────────────
            .child(
                div()
                    .flex()
                    .flex_row()
                    .items_center()
                    .justify_between()
                    .px_4()
                    .py_3()
                    .bg(colors::MANTLE)
                    .border_b_1()
                    .border_color(colors::SURFACE0)
                    .child(
                        div()
                            .flex()
                            .flex_row()
                            .items_center()
                            .gap_3()
                            .child(
                                div()
                                    .text_color(colors::TEXT)
                                    .text_sm()
                                    .font_weight(FontWeight::SEMIBOLD)
                                    .font_family("monospace")
                                    .child(title),
                            ),
                    )
                    .when(!is_empty, |d| {
                        d.child(
                            div()
                                .flex()
                                .flex_row()
                                .items_center()
                                .gap_2()
                                .child(
                                    div()
                                        .text_color(colors::OVERLAY0)
                                        .text_xs()
                                        .child(format!(
                                            "{} file{}",
                                            stats.files,
                                            if stats.files == 1 { "" } else { "s" }
                                        )),
                                )
                                .child(stat_pill(stats.added,   colors::GREEN, "+"))
                                .child(stat_pill(stats.removed, colors::RED,   "−"))
                        )
                    }),
            )
            // ── content ───────────────────────────────────────────────────────
            .child(
                div()
                    .flex_1()
                    .overflow_y_scroll()
                    .overflow_x_hidden()
                    .when(is_empty, |d| {
                        d.flex()
                            .items_center()
                            .justify_center()
                            .child(
                                div()
                                    .flex()
                                    .flex_col()
                                    .items_center()
                                    .gap_3()
                                    .p_8()
                                    .child(
                                        div()
                                            .text_color(colors::SURFACE2)
                                            .text_4xl()
                                            .child("✓"),
                                    )
                                    .child(
                                        div()
                                            .text_color(colors::OVERLAY0)
                                            .text_sm()
                                            .text_center()
                                            .child(if selected.is_none() {
                                                "Select a workspace in the sidebar."
                                            } else {
                                                "Clean — no diff against base branch."
                                            }),
                                    ),
                            )
                    })
                    .when(!is_empty, |d| {
                        d.children(diff_lines.iter().map(render_line))
                    }),
            )
    }
}

